  const [editingConstraintId, setEditingConstraintId] = useState<string | null>(null);
  const [jointCapacities, setJointCapacities] = useState<Record<JointGroup, JointCapacityProfile>>(DEFAULT_CAPACITIES);

  const [reactionForces, setReactionForces] = useState<VisualForce[]>([]);
  const [calculatedTorques, setCalculatedTorques] = useState<Record<string, Vector3>>({});
  const [neuralCosts, setNeuralCosts] = useState<Record<string, number>>({});

  const [hybridConstraints, setHybridConstraints] = useState<Record<string, HybridConstraintConfig>>({});

  const selectedBoneConstraint = useMemo(() => 
    constraints.find(c => c.boneId === selectedBone), 
  [constraints, selectedBone]);

  const hasConstraint = (boneId: string) => constraints.some(c => c.boneId === boneId);

  const getVisualVector = (f: ForceConfig): Vector3 => {
      return { x: f.x * f.magnitude, y: f.y * f.magnitude, z: f.z * f.magnitude };
  };

  const measurements = useMemo<Measurement[]>(() => {
      if (!selectedBone) return [];
      const list: Measurement[] = [];
      const vec = posture[selectedBone];
      if (vec) {
        if (selectedBone.includes('Femur')) {
            const angle = Math.round(Math.acos(vec.y) * 180 / Math.PI);
            list.push({ label: 'Hip Angle', value: `${angle}°`, subtext: 'Relative' });

            const absRot = getAbsoluteRotation(selectedBone, posture, twists);
            list.push({ label: 'Rotation', value: `${absRot}°`, subtext: 'Int/Ext' });
        } else if (selectedBone.includes('Humerus')) {
             const angle = Math.round(Math.acos(vec.y) * 180 / Math.PI);
             list.push({ label: 'Shoulder Angle', value: `${angle}°`, subtext: 'Relative' });

             const absRot = getAbsoluteRotation(selectedBone, posture, twists);
             list.push({ label: 'Rotation', value: `${absRot}°`, subtext: 'Int/Ext' });
        }
      }
      return list;
  }, [selectedBone, posture, twists]);

  const BONE_ORDER = ['lClavicle', 'rClavicle', 'lHumerus', 'rHumerus', 'lFemur', 'rFemur', 'lForearm', 'rForearm', 'lTibia', 'rTibia'];

  const solveConstraints = (tempPosture: Posture, currentTwists: Record<string, number>): Posture => {
      let correctedPosture = { ...tempPosture };
      let changed = false;

      BONE_ORDER.forEach(boneId => {
          const config = hybridConstraints[boneId] as HybridConstraintConfig | undefined;
          if (!config || !config.active) return;

          const kinematics = calculateKinematics(correctedPosture, currentTwists);
          const startPos = kinematics.boneStartPoints[boneId];
          const parentFrame = kinematics.jointFrames[boneId];

          if (!startPos || !parentFrame) return;

          const len = BONE_LENGTHS[boneId] || 0;
          const N = normalize(config.normal);
          const P_lock = config.center;

          const localDir = correctedPosture[boneId];
          const worldDir = localToWorld(parentFrame, localDir);
          const proposedTip = add(startPos, mul(worldDir, len));

          const vToTip = sub(proposedTip, P_lock);
          const dist = dotProduct(vToTip, N);

          if (Math.abs(dist) < 0.1) return; 

          const vToStart = sub(startPos, P_lock);
          const distStart = dotProduct(vToStart, N);
          const circleCenter = sub(startPos, mul(N, distStart));

          const radSq = (len * len) - (distStart * distStart);
          let finalTip: Vector3;

          if (radSq < 0) {
              const dirToPlane = mul(N, -Math.sign(distStart));
              finalTip = add(startPos, mul(dirToPlane, len));
          } else {
              const radius = Math.sqrt(radSq);
              const vToProposed = sub(proposedTip, P_lock);
              const distProposed = dotProduct(vToProposed, N);
              const proposedOnPlane = sub(proposedTip, mul(N, distProposed));
              const vCenterToProposed = sub(proposedOnPlane, circleCenter);
              const mag = magnitude(vCenterToProposed);

              if (mag < 0.001) {
                  finalTip = proposedOnPlane; 
              } else {
                  finalTip = add(circleCenter, mul(vCenterToProposed, radius / mag));
              }
          }

          const finalWorldDir = normalize(sub(finalTip, startPos));
          const finalLocalDir = worldToLocal(parentFrame, finalWorldDir);

          correctedPosture[boneId] = finalLocalDir;
          changed = true;
      });

      return changed ? correctedPosture : tempPosture;
  };

  const validateConfiguration = (p: Posture, t: Record<string, number>): boolean => {
      const k = calculateKinematics(p, t);
      for (const [boneId, configRaw] of Object.entries(hybridConstraints)) {
          const config = configRaw as HybridConstraintConfig;
          if (!config.active) continue;

          const tip = k.boneEndPoints[boneId];
          if (!tip) continue;

          const N = normalize(config.normal);
          const v = sub(tip, config.center);
          const dist = Math.abs(dotProduct(v, N));

          if (dist > 1.0) return false;
      }
      return true;
  };

  const validatePosture = (p: Posture): boolean => {
      return validateConfiguration(p, twists);
  };

  const syncTwistsToPosture = (finalPosture: Posture, currentTwists: Record<string, number>): Record<string, number> => {
      const k = calculateKinematics(finalPosture, currentTwists);
      const newTwists = { ...currentTwists };

      const syncLimb = (root: string, mid: string) => {
          const rootStart = k.boneStartPoints[root];
          const midStart = k.boneStartPoints[mid]; 
          const endStart = k.boneEndPoints[mid];

          if (!rootStart || !midStart || !endStart) return;

          const vFemur = normalize(sub(midStart, rootStart));
          const vTibia = normalize(sub(endStart, midStart));

          if (dotProduct(vFemur, vTibia) > 0.99) return; 

          const actualKneeAxis = normalize(crossProduct(vFemur, vTibia));

          let baseFrame: Frame;
          if (root.includes('Humerus') || root.includes('Femur')) {
              baseFrame = getNeutralAlignedFrame(vFemur);
          } else {
              const rootFrame = createRootFrame({x: 0, y: 1, z: 0});
              baseFrame = transportFrame(rootFrame, vFemur);
          }

          const neutralKneeAxis = baseFrame.x;

          const cross = crossProduct(neutralKneeAxis, actualKneeAxis);
          const sign = dotProduct(cross, vFemur) > 0 ? 1 : -1;
          const angleRad = Math.atan2(magnitude(cross), dotProduct(neutralKneeAxis, actualKneeAxis));
          let angleDeg = Math.round(angleRad * 180 / Math.PI * sign);

          // Enforce Limits
          if (ROTATION_LIMITS[root]) {
              const { min, max } = ROTATION_LIMITS[root];
              // Normalize angle if needed to prevent snapping at 180/-180 boundary
              if (angleDeg < min && (angleDeg + 360) <= max) {
                  angleDeg += 360;
              } else if (angleDeg > max && (angleDeg - 360) >= min) {
                  angleDeg -= 360;
              }
              angleDeg = clamp(angleDeg, min, max);
          }

          newTwists[root] = angleDeg;
      };

      syncLimb('lFemur', 'lTibia');
      syncLimb('rFemur', 'rTibia');
      syncLimb('lHumerus', 'lForearm');
      syncLimb('rHumerus', 'rForearm');

      return newTwists;
  };

  const updatePostureState = (updater: (prev: Posture) => Posture) => {
    const updateFn = (setPostureFn: React.Dispatch<React.SetStateAction<Posture>>, setTwistFn: React.Dispatch<React.SetStateAction<Record<string, number>>>) => {
        setPostureFn(prev => {
            let next = updater(prev);
            next = solveConstraints(next, twists);
            if (!validatePosture(next)) return prev;
            setTwistFn(prevTwists => {
                const newTwists = syncTwistsToPosture(next, prevTwists);
                setTwists(newTwists);
                return newTwists;
            });
            setPosture(next); 
            return next;
        });
    };

    if (poseMode === 'start') {
        updateFn(setStartPosture, setStartTwists);
    } else {
        updateFn(setEndPosture, setEndTwists);
    }
  };

  const updateTwistState = (updater: (prev: Record<string, number>) => Record<string, number>) => {
      if (poseMode === 'start') { setStartTwists(updater); setTwists(updater); } 
      else { setEndTwists(updater); setTwists(updater); }
  };

  const skeletalData = useMemo(() => {
    return calculateKinematics(posture, twists);
  }, [posture, twists]);

  const applyConstraints = (boneId: string, proposedVec: Vector3): Vector3 => {
      const activeConstraints = constraints.filter(c => c.boneId === boneId);
      if (activeConstraints.length === 0) return proposedVec;
      return posture[boneId] || proposedVec;
  };

  const handleScapulaChange = (axis: 'elevation' | 'protraction', val: number) => {
      if (!selectedBone) return;
      if (isPlaying) setIsPlaying(false);

      const current = posture[selectedBone];
      let newVec = { ...current };
      if (axis === 'elevation') newVec.y = -val;
      else if (axis === 'protraction') newVec.z = -val; 

      newVec = applyConstraints(selectedBone, newVec);

      const parentFrame = skeletalData.jointFrames[selectedBone];
      const proposedWorld = localToWorld(parentFrame, newVec);
      const finalLocal = worldToLocal(parentFrame, proposedWorld);

      updatePostureState(prev => {
          const next = { ...prev, [selectedBone]: finalLocal };
          if (symmetryMode) {
              const opp = getOppositeBone(selectedBone);
              if (opp) next[opp] = { x: -finalLocal.x, y: finalLocal.y, z: finalLocal.z };
          }
          return next;
      });
  };

  const handleHingeChange = (val: number) => {
      if (!selectedBone) return;
      if (isPlaying) setIsPlaying(false);

      let newVec = { x: 0, y: 0, z: 0 };
      const rad = (val * Math.PI) / 180;
      if (selectedBone.includes('Foot')) {
          newVec = { x: 0, y: Math.sin(rad), z: -Math.cos(rad) };
      } else {
          // Both knee and elbow now use direction 1 because of the frame flip in Humerus/Femur
          const direction = 1; 
          newVec = { x: 0, y: Math.cos(rad), z: direction * Math.sin(rad) };
      }

      const constrainedVec = applyConstraints(selectedBone, newVec);

      updatePostureState(prev => {
          const next = { ...prev, [selectedBone]: constrainedVec };
          if (symmetryMode) {
              const opp = getOppositeBone(selectedBone);
              if (opp) next[opp] = { ...constrainedVec }; 
          }
          return next;
      });
  };

  const updateHybridConstraint = (boneId: string, updates: Partial<HybridConstraintConfig>) => {
      setHybridConstraints(prev => {
          const existing = prev[boneId] || { active: false, normal: { x: 0, y: 1, z: 0 }, center: { x: 0, y: 0, z: 0 } };
          if (updates.active && !existing.active) {
              const currentTip = skeletalData.boneEndPoints[boneId];
              if (currentTip) {
                  return { ...prev, [boneId]: { ...existing, ...updates, center: currentTip } };
              }
          }
          return { ...prev, [boneId]: { ...existing, ...updates } };
      });

      if (updates.active === true && !/Forearm|Tibia/.test(boneId)) {
          const currentVec = posture[boneId];
          if (currentVec) {
             const len = BONE_LENGTHS[boneId] || 100;
             setTargetPos({ x: currentVec.x * len, y: currentVec.y * len, z: currentVec.z * len });
          }
      }
  };

  const lockedPlanes = useMemo<VisualPlane[]>(() => {
    return (Object.entries(hybridConstraints) as [string, HybridConstraintConfig][])
        .filter(([_, config]) => config.active)
        .map(([id, config]) => ({
            id: `hybrid-${id}`,
            center: config.center,
            normal: normalize(config.normal),
            size: 200,
            color: '#8b5cf6'
        }));
  }, [hybridConstraints]);

  const handlePointChange = (axis: keyof Vector3, newValue: number) => {
    if (!selectedBone || !targetPos) return;
    if (isPlaying) setIsPlaying(false);

    if (selectedBone.includes('Clavicle')) {
        const proposedPos = { ...posture[selectedBone], [axis]: newValue };
        const constrainedPos = applyConstraints(selectedBone, proposedPos);
        setTargetPos(constrainedPos);
        updatePostureState(prev => {
            const next = { ...prev, [selectedBone]: constrainedPos };
            if (symmetryMode) {
                const opp = getOppositeBone(selectedBone);
                if (opp) next[opp] = { x: -constrainedPos.x, y: constrainedPos.y, z: constrainedPos.z };
            }
            return next;
        });
        return;
    }

    const internalVal = -newValue;
    const newTarget = { ...targetPos, [axis]: internalVal };
    setTargetPos(newTarget);

    if (targetReferenceBone) {
        const rootBone = targetReferenceBone;
        const childBone = selectedBone; 

        const isRootConstrained = constraints.some(c => c.boneId === rootBone);
        const isChildConstrained = constraints.some(c => c.boneId === childBone); 
        let middleBone = '';
        if (rootBone.includes('Femur')) middleBone = rootBone.replace('Femur', 'Tibia');
        else if (rootBone.includes('Humerus')) middleBone = rootBone.replace('Humerus', 'Forearm');
        const isMiddleConstrained = constraints.some(c => c.boneId === middleBone);

        if (isRootConstrained || isMiddleConstrained) return; 

        const len1 = BONE_LENGTHS[rootBone];
        const len2 = BONE_LENGTHS[middleBone];

        let newRootVec = posture[rootBone];
        let newMidVecLocal = posture[middleBone];

        const isRight = rootBone.startsWith('r');
        const targetDirWorld = normalize(newTarget);

        // Use uniform Neutral Frame generation for both limbs to maintain consistent rotation signs
        let baseFrame: Frame;
        if (rootBone.includes('Humerus') || rootBone.includes('Femur')) {
             baseFrame = getNeutralAlignedFrame(targetDirWorld);
        } else {
             const rootFrame = createRootFrame({x:0, y:1, z:0});
             baseFrame = transportFrame(rootFrame, targetDirWorld);
        }

        // Use Clamped Twist for IK Calculation to ensure kinematic consistency
        let currentTwist = twists[rootBone] || 0;
        if (ROTATION_LIMITS[rootBone]) {
            currentTwist = clamp(currentTwist, ROTATION_LIMITS[rootBone].min, ROTATION_LIMITS[rootBone].max);
        }

        const twistedFrame = twistFrame(baseFrame, currentTwist);

        let biasScale = 1;
        if (rootBone.includes('Femur')) {
            biasScale = -1;
        } else {
            biasScale = isRight ? -1 : 1;
        }

        const dynamicBias = mul(twistedFrame.z, biasScale); 

        const forwardSolution = solveTwoBoneIK({x:0,y:0,z:0}, newTarget, len1, len2, dynamicBias);

        if (forwardSolution) {
            const rootFrame = createRootFrame({x:0, y:1, z:0});
            newRootVec = worldToLocal(rootFrame, forwardSolution.vec1);

            let frame1: Frame;
            if (rootBone.includes('Humerus') || rootBone.includes('Femur')) {
                frame1 = getNeutralAlignedFrame(forwardSolution.vec1);
            } else {
                frame1 = transportFrame(rootFrame, forwardSolution.vec1);
            }

            // The child's local vector must be relative to the TWISTED parent frame
            const frame1Twisted = twistFrame(frame1, currentTwist);
            newMidVecLocal = worldToLocal(frame1Twisted, forwardSolution.vec2);
        }

        updatePostureState(prev => {
            const next = { ...prev, [rootBone]: newRootVec, [middleBone]: newMidVecLocal };
            if (symmetryMode) {
                const oppRoot = getOppositeBone(rootBone);
                const oppMid = getOppositeBone(middleBone);
                if (oppRoot) next[oppRoot] = { ...newRootVec, x: -newRootVec.x };
                if (oppMid) next[oppMid] = { ...newMidVecLocal, x: -newMidVecLocal.x };
            }
            return next;
        });
        return;
    }

    const newDirLocal = normalize(newTarget);
    const constrainedLocal = applyConstraints(selectedBone, newDirLocal);

    updatePostureState(prev => {
        const next = { ...prev, [selectedBone]: constrainedLocal };
        if (symmetryMode) {
            const opp = getOppositeBone(selectedBone);
            if (opp) next[opp] = { ...constrainedLocal, x: -constrainedLocal.x };
        }
        return next;
    });
  };

  const handleRotationChange = (val: number) => {
    if (!selectedBone) return;
    if (isPlaying) setIsPlaying(false);

    const currentP = poseMode === 'start' ? startPosture : endPosture;
    const currentT = poseMode === 'start' ? startTwists : endTwists;

    // Constrain input value if limits exist
    let allowedVal = val;
    if (ROTATION_LIMITS[selectedBone]) {
        allowedVal = clamp(val, ROTATION_LIMITS[selectedBone].min, ROTATION_LIMITS[selectedBone].max);
    }

    const currentAbs = getAbsoluteRotation(selectedBone, currentP, currentT);
    const delta = allowedVal - currentAbs;
    const newTwist = (currentT[selectedBone] || 0) + delta;

    const nextTwists = { ...currentT, [selectedBone]: newTwist };
    if (symmetryMode) {
        const opp = getOppositeBone(selectedBone);
        // With aligned frames (Positive=External, Negative=Internal for both), symmetry copies exact value
        if (opp) nextTwists[opp] = newTwist;
    }

    const resolvedPosture = solveConstraints(currentP, nextTwists);

    if (!validateConfiguration(resolvedPosture, nextTwists)) return;

    if (poseMode === 'start') {
        setStartPosture(resolvedPosture);
        setStartTwists(nextTwists);
    } else {
        setEndPosture(resolvedPosture);
        setEndTwists(nextTwists);
    }
    setPosture(resolvedPosture);
    setTwists(nextTwists);
  };

  const isScapula = selectedBone ? selectedBone.includes('Clavicle') : false;
  const isHinge = selectedBone ? /Forearm|Tibia|Foot/.test(selectedBone) : false;

  const getHingeConfig = (bone: string) => {
      const isConstrained = hasConstraint(bone);
      if (bone.includes('Forearm')) return { label: 'Elbow Flexion', min: 0, max: 150, default: 0 };
      if (bone.includes('Tibia')) return { label: 'Knee Flexion', min: 0, max: 150, default: 0 };
      if (bone.includes('Foot')) return { label: 'Ankle Dorsi/Plantar', min: isConstrained ? -50 : -90, max: isConstrained ? 50 : 90, default: 0 };
      return null;
  };

  const getCurrentHingeAngle = (bone: string) => {
      const vec = posture[bone] || { x: 0, y: 1, z: 0 };
      if (bone.includes('Foot')) return Math.round(Math.asin(vec.y) * 180 / Math.PI); 
      return Math.round(Math.acos(vec.y) * 180 / Math.PI);
  };

  const displayTwist = useMemo(() => {
    if (!selectedBone) return 0;
    // Prefer using the twist state directly if it exists, as it's the source of truth for the slider.
    // getAbsoluteRotation is used for validation and measurement display.
    if (twists[selectedBone] !== undefined) return twists[selectedBone];
    return getAbsoluteRotation(selectedBone, posture, twists);
  }, [selectedBone, posture, twists]);

  // --- FORCE & CONSTRAINT MANAGEMENT ---
  const addNewForce = () => {
    const newForce: ForceConfig = { id: Date.now().toString(), name: 'New Force', boneId: selectedBone || 'rForearm', position: 1, x: 0, y: -1, z: 0, magnitude: 10 };
    setForces([...forces, newForce]);
    setEditingForceId(newForce.id);
    setActiveTab('kinetics');
  };

  const updateForce = (id: string, field: keyof ForceConfig, value: any) => {
    setForces(prev => prev.map(f => f.id === id ? { ...f, [field]: value } : f));
  };

  const deleteForce = (id: string) => { setForces(prev => prev.filter(f => f.id !== id)); };

  const addNewConstraint = () => {
    const boneId = selectedBone || 'rForearm';
    const currentLocal = posture[boneId];
    if (!currentLocal) return;
    const capturedVector = { ...currentLocal };

    const newConstraint: ConstraintConfig = { 
        id: Date.now().toString(), 
        type: 'vector', 
        boneId: boneId, 
        position: 1, 
        restrictions: [capturedVector] 
    };
    setConstraints([...constraints, newConstraint]);
    setEditingConstraintId(newConstraint.id);
  };

  const updateConstraint = (id: string, field: keyof ConstraintConfig, value: any) => {
    setConstraints(prev => prev.map(c => c.id === id ? { ...c, [field]: value } : c));
  };

  const updateConstraintRestriction = (id: string, index: number, axis: keyof Vector3, value: number) => {
      setConstraints(prev => prev.map(c => {
          if (c.id !== id) return c;
          const newRestrictions = [...c.restrictions];
          if (newRestrictions[index]) {
              newRestrictions[index] = { ...newRestrictions[index], [axis]: value };
          }
          return { ...c, restrictions: newRestrictions };
      }));
  };

  const addConstraintRestriction = (id: string) => {
      setConstraints(prev => prev.map(c => {
          if (c.id !== id) return c;
          const currentLocal = posture[c.boneId] || {x:0, y:1, z:0};
          return { ...c, restrictions: [...c.restrictions, {...currentLocal}] };
      }));
  };

  const removeConstraintRestriction = (id: string, index: number) => {
      setConstraints(prev => prev.map(c => {
          if (c.id !== id) return c;
          return { ...c, restrictions: c.restrictions.filter((_, i) => i !== index) };
      }));
  };

  const deleteConstraint = (id: string) => { setConstraints(prev => prev.filter(c => c.id !== id)); };

  const toggleSymmetry = () => setSymmetryMode(prev => !prev);

  const resetModel = () => {
    setStartPosture(DEFAULT_POSTURE);
    setEndPosture(DEFAULT_POSTURE);
    setStartTwists(DEFAULT_TWISTS);
    setEndTwists(DEFAULT_TWISTS);
    setPosture(DEFAULT_POSTURE);
    setTwists(DEFAULT_TWISTS);
    setSelectedBone(null);
    setTargetPos(null);
    setTargetReferenceBone(null);
    setForces([]);
    setConstraints([]);
    setSymmetryMode(false);
    setIsPlaying(false);
    setHybridConstraints({});
  };

  const handleBoneSelect = (boneId: string) => {
    if (selectedBone === boneId) {
        setSelectedBone(null);
        setTargetPos(null);
        setTargetReferenceBone(null);
    } else {
        setSelectedBone(boneId);
        const boneIsHinge = /Forearm|Tibia|Foot/.test(boneId);

        if (boneIsHinge) {
            setTargetPos(null);
        } else {
            const currentP = poseMode === 'start' ? startPosture : endPosture;
            const vec = currentP[boneId];
            if (vec) {
                 if (boneId.includes('Clavicle')) {
                     setTargetPos({ ...vec });
                 } else {
                     const len = BONE_LENGTHS[selectedBone] || 100;
                     setTargetPos({ x: vec.x * len, y: vec.y * len, z: vec.z * len });
                 }
            } else {
                setTargetPos(null);
            }
        }

        if (boneId === 'lFoot') setTargetReferenceBone('lFemur');
        else if (boneId === 'rFoot') setTargetReferenceBone('rFemur');
        else if (boneId === 'lForearm') setTargetReferenceBone('lHumerus');
        else if (boneId === 'rForearm') setTargetReferenceBone('rHumerus');
        else setTargetReferenceBone(null);
    }
  };

  const switchPoseMode = (mode: 'start' | 'end') => {
      setPoseMode(mode);
      if (mode === 'start') {
          setPosture(startPosture);
          setTwists(startTwists);
      } else {
          setPosture(endPosture);
          setTwists(endTwists);
      }
      setTargetPos(null);
  };

  const copyStartToEnd = () => {
      setEndPosture(startPosture);
      setEndTwists(startTwists);
      if (poseMode === 'end') {
          setPosture(startPosture);
          setTwists(startTwists);
      }
  };

  const updateCapacity = (group: JointGroup, action: string, field: keyof CapacityConfig, value: number) => {
    setJointCapacities(prev => ({
        ...prev,
        [group]: {
            ...prev[group],
            [action]: {
                ...prev[group][action],
                [field]: value
            }
        }
    }));
  };

  const currentElevationDeg = useMemo(() => {
    if (!selectedBone || !isScapula) return 0;
    const vec = posture[selectedBone];
    return vec ? Math.round(-vec.y) : 0;
  }, [selectedBone, posture, isScapula]);

  const currentProtractionDeg = useMemo(() => {
    if (!selectedBone || !isScapula) return 0;
    const vec = posture[selectedBone];
    return vec ? Math.round(-vec.z) : 0;
  }, [selectedBone, posture, isScapula]);

  // ANIMATION LOOP
  useEffect(() => {
    if (isPlaying) {
      const startTime = Date.now();
      const cycleDuration = 3000;
      const animate = () => {
        const now = Date.now();
        const elapsed = now - startTime;
        const phase = (elapsed % cycleDuration) / cycleDuration;
        let t = 0;
        if (phase < 0.5) { t = phase * 2; } else { t = 2 - (phase * 2); }
        const newPosture: Posture = {};
        const newTwists: Record<string, number> = {};
        Object.keys(startPosture).forEach(boneId => {
            const startV = startPosture[boneId];
            const endV = endPosture[boneId] || startV;
            newPosture[boneId] = interpolateVector(startV, endV, t);
        });
        const allTwistKeys = new Set([...Object.keys(startTwists), ...Object.keys(endTwists)]);
        allTwistKeys.forEach(boneId => {
            const startT = startTwists[boneId] || 0;
            const endT = endTwists[boneId] || 0;
            newTwists[boneId] = interpolateScalar(startT, endT, t);
        });
        setPosture(newPosture);
        setTwists(newTwists);
        animationRef.current = requestAnimationFrame(animate);
      };
      animationRef.current = requestAnimationFrame(animate);
    } else {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      if (poseMode === 'start') { setPosture(startPosture); setTwists(startTwists); } 
      else { setPosture(endPosture); setTwists(endTwists); }
    }
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); };
  }, [isPlaying, startPosture, endPosture, startTwists, endTwists, poseMode]);

  // INITIALIZE TARGET POS ON SELECTION
  const prevSelection = useRef<string | null>(null);
  const prevMode = useRef<string>('start');

