    locations['Spine'] = { x: 0, y: CONFIG.TORSO_LEN/2, z: 0 };
    const neckBase = { x: 0, y: -CONFIG.TORSO_LEN/2, z: 0 };
    boneStart['spine'] = neckBase;
    boneEnd['spine'] = locations['Spine'];

    locations['lHip'] = { x: -CONFIG.HIP_WIDTH, y: CONFIG.TORSO_LEN/2, z: 0 };
    locations['rHip'] = { x: CONFIG.HIP_WIDTH, y: CONFIG.TORSO_LEN/2, z: 0 };
    locations['lShoulderOrigin'] = neckBase;
    locations['rShoulderOrigin'] = neckBase;

    const rootFrame = createRootFrame({x:0, y:1, z:0});
    frames['lClavicle'] = rootFrame;
    frames['rClavicle'] = rootFrame;
    frames['lHip'] = rootFrame;
    frames['rHip'] = rootFrame;

    const calculateChain = (name: string, child: string, grandChild: string, start: Vector3, parentFrame: Frame, len1: number, len2: number, len3: number) => {
        const dir1Local = posture[name] || {x:0, y:1, z:0};
        const dir1World = localToWorld(parentFrame, dir1Local);

        let frame1Base: Frame;
        if (name.includes('Humerus') || name.includes('Femur')) {
             frame1Base = createRootFrame(dir1World);
        } else {
             frame1Base = transportFrame(parentFrame, dir1World);
        }

        // Match twist logic
        let twist = twists[name] || 0;
        if (name.startsWith('l')) twist = -twist;

        const frame1Twisted = twistFrame(frame1Base, twist);
        const end1 = add(start, mul(frame1Twisted.y, len1));
        boneStart[name] = start;
        boneEnd[name] = end1;
        frames[name] = parentFrame; 

        let end2 = end1;
        let frame2Twisted = frame1Twisted;
        if (child) {
            const dir2Local = posture[child] || {x:0, y:1, z:0};
            const dir2World = localToWorld(frame1Twisted, dir2Local);
            const frame2Base = transportFrame(frame1Twisted, dir2World);
            frame2Twisted = twistFrame(frame2Base, twists[child] || 0);
            end2 = add(end1, mul(frame2Twisted.y, len2));
            boneStart[child] = end1;
            boneEnd[child] = end2;
            frames[child] = frame1Twisted;
        }
        if (grandChild) {
             const dir3Local = posture[grandChild] || {x:0, y:0, z:1};
             const dir3World = localToWorld(frame2Twisted, dir3Local);
             const frame3Base = transportFrame(frame2Twisted, dir3World);
             const frame3Twisted = twistFrame(frame3Base, twists[grandChild] || 0);
             const end3 = add(end2, mul(frame3Twisted.y, len3));
             boneStart[grandChild] = end2;
             boneEnd[grandChild] = end3;
             frames[grandChild] = frame2Twisted;
        }
    };

    const lClavOffset = posture['lClavicle'] || { x: -25, y: 0, z: 0 };
    const rClavOffset = posture['rClavicle'] || { x: 25, y: 0, z: 0 };
    const lShoulderPos = add(neckBase, lClavOffset);
    const rShoulderPos = add(neckBase, rClavOffset);

    boneStart['lClavicle'] = neckBase;
    boneEnd['lClavicle'] = lShoulderPos;
    boneStart['rClavicle'] = neckBase;
    boneEnd['rClavicle'] = rShoulderPos;

    calculateChain('lFemur', 'lTibia', 'lFoot', locations['lHip'], rootFrame, BONE_LENGTHS.lFemur, BONE_LENGTHS.lTibia, BONE_LENGTHS.lFoot);
    calculateChain('rFemur', 'rTibia', 'rFoot', locations['rHip'], rootFrame, BONE_LENGTHS.rFemur, BONE_LENGTHS.rTibia, BONE_LENGTHS.rFoot);
    calculateChain('lHumerus', 'lForearm', '', lShoulderPos, rootFrame, BONE_LENGTHS.lHumerus, BONE_LENGTHS.lForearm, 0);
    calculateChain('rHumerus', 'rForearm', '', rShoulderPos, rootFrame, BONE_LENGTHS.rHumerus, BONE_LENGTHS.rForearm, 0);

    return { boneStart, boneEnd, locations };
  }, [posture, twists]);

  // Projection Logic
  const toRad = (deg: number) => deg * Math.PI / 180;
  const project = (v: Vector3) => {
      // Rotate Y (Yaw)
      const cosY = Math.cos(toRad(camera.yaw));
      const sinY = Math.sin(toRad(camera.yaw));
      const x1 = v.x * cosY + v.z * sinY;
      const z1 = -v.x * sinY + v.z * cosY;

      // Rotate X (Pitch)
      const cosX = Math.cos(toRad(camera.pitch));
      const sinX = Math.sin(toRad(camera.pitch));
      const y2 = v.y * cosX - z1 * sinX;

      const scale = 2.5;
      return { x: 400 + x1 * scale, y: 300 + y2 * scale };
  };

  // Mouse Handlers
  const handleMouseDown = (e: React.MouseEvent) => {
      isDragging.current = true;
      lastMouse.current = { x: e.clientX, y: e.clientY };
  };
  const handleMouseMove = (e: React.MouseEvent) => {
      if (!isDragging.current) return;
      const dx = e.clientX - lastMouse.current.x;
      const dy = e.clientY - lastMouse.current.y;
      setCamera(prev => ({ pitch: prev.pitch - dy * 0.5, yaw: prev.yaw + dx * 0.5 }));
      lastMouse.current = { x: e.clientX, y: e.clientY };
  };
  const handleMouseUp = () => isDragging.current = false;

  const renderBone = (id: string, start: Vector3, end: Vector3, color: string = '#cbd5e1', width: number = 6) => {
      const p1 = project(start);
      const p2 = project(end);
      return (
          <g key={id} onClick={(e) => { e.stopPropagation(); onSelectBone(id); }} className="cursor-pointer hover:opacity-80">
             <line x1={p1.x} y1={p1.y} x2={p2.x} y2={p2.y} stroke={selectedBone === id ? '#4f46e5' : color} strokeWidth={width} strokeLinecap="round" />
          </g>
      );
  };

  // Render Skeleton
  const bones = Object.keys(skeletalData.boneStart).map(id => {
     return renderBone(id, skeletalData.boneStart[id], skeletalData.boneEnd[id]);
  });

  // Render Target Position
  let targetVisual = null;
  if (targetPos && selectedBone && skeletalData.boneStart[selectedBone]) {
      let origin = {x:0, y:0, z:0};
      let isWorldVector = false;

      if (targetReferenceBone) {
          origin = skeletalData.boneStart[targetReferenceBone] || {x:0, y:0, z:0};
          isWorldVector = true;
      } else if (selectedBone.includes('Clavicle')) {
          origin = skeletalData.boneStart['spine'];
          isWorldVector = true;
      }

      if (isWorldVector) {
          const end = add(origin, targetPos);
          const p1 = project(origin);
          const p2 = project(end);
          targetVisual = (
              <g key="target">
                 <line x1={p1.x} y1={p1.y} x2={p2.x} y2={p2.y} stroke="#10b981" strokeWidth="2" strokeDasharray="4" />
                 <circle cx={p2.x} cy={p2.y} r="4" fill="#10b981" />
              </g>
          );
      }
  }

  // Render Forces
  const forceVisuals = externalForces.map(f => {
      const startBone = skeletalData.boneStart[f.boneId];
      const endBone = skeletalData.boneEnd[f.boneId];
      if (!startBone || !endBone) return null;

      const origin = add(startBone, mul(sub(endBone, startBone), f.position));
      const end = add(origin, mul(f.vector, 2)); 
      const p1 = project(origin);
      const p2 = project(end);

      return (
          <g key={f.id}>
             <line x1={p1.x} y1={p1.y} x2={p2.x} y2={p2.y} stroke={f.color || "#ef4444"} strokeWidth="3" markerEnd="url(#arrowhead)" />
          </g>
      );
  });

  // Render Planes
  const planeVisuals = planes.map(p => {
      const center = project(p.center);
      return (
          <g key={p.id}>
              <circle cx={center.x} cy={center.y} r={p.size / 5} fill={p.color || "rgba(139, 92, 246, 0.2)"} stroke={p.color || "rgba(139, 92, 246, 0.5)"} />
              {(() => {
                  const end = add(p.center, mul(normalize(p.normal), 50));
                  const pEnd = project(end);
                  return <line x1={center.x} y1={center.y} x2={pEnd.x} y2={pEnd.y} stroke={p.color} strokeWidth="2" />;
              })()}
          </g>
      );
  });

  return (
    <div className="w-full h-full cursor-move" onMouseDown={handleMouseDown} onMouseMove={handleMouseMove} onMouseUp={handleMouseUp} onMouseLeave={handleMouseUp}>
       <svg width="100%" height="100%" viewBox="0 0 800 600" preserveAspectRatio="xMidYMid slice">
         <defs>
            <marker id="arrowhead" markerWidth="10" markerHeight="7" refX="9" refY="3.5" orient="auto">
                <polygon points="0 0, 10 3.5, 0 7" fill="#ef4444" />
            </marker>
         </defs>
         <line x1="100" y1="500" x2="700" y2="500" stroke="#f1f5f9" strokeWidth="2" />
         {planeVisuals}
         {bones}
         {forceVisuals}
         {targetVisual}
       </svg>
       <div className="absolute bottom-4 right-4 bg-black/80 text-white text-xs p-2 rounded">
          Pitch: {Math.round(camera.pitch)}° Yaw: {Math.round(camera.yaw)}°
       </div>
    </div>
  );
};

