                                               <div className="flex items-center gap-2">
                                                   <input type="range" min="0" max="180" value={config.angle} onChange={(e) => updateCapacity(group as JointGroup, action, 'angle', parseFloat(e.target.value))} className="flex-1 bio-range text-purple-500" />
                                                   <span className="text-[10px] font-mono font-bold text-gray-500 w-8 text-right">{config.angle}°</span>
                                               </div>
