            {activeTab === 'kinetics' && <Zap className="w-5 h-5 text-orange-500" />}
            {activeTab === 'constraints' && <Anchor className="w-5 h-5 text-emerald-600" />}
            {activeTab === 'torque' && <Scale className="w-5 h-5 text-gray-800" />}
