// Helper to determine if a change makes the state *worse* (more violating)
// This prevents getting stuck if you start in an invalid state, but blocks moving further into violation
const checkPlanarViolation = (proposedPosture: Posture, proposedTwists: Record<string, number>, currentPosture: Posture, currentTwists: Record<string, number>): boolean => {
    const kProposed = calculateKinematics(proposedPosture, proposedTwists);
    const kCurrent = calculateKinematics(currentPosture, currentTwists);

    for (const [boneId, constraints] of Object.entries(hybridConstraints)) {
        const activeConstraints = (constraints as PlanarConstraint[]).filter(c => c.active);
        if (activeConstraints.length === 0) continue;

        const tipProp = kProposed.boneEndPoints[boneId];
        const tipCurr = kCurrent.boneEndPoints[boneId];
        if (!tipProp || !tipCurr) continue;

        for (const c of activeConstraints) {
            const N = normalize(c.normal);
            const vProp = sub(tipProp, c.center);
            const vCurr = sub(tipCurr, c.center);

            const distProp = dotProduct(vProp, N);
            const distCurr = dotProduct(vCurr, N);

            // Strict Check:
            // If we are "touching" or inside the wall (dist < 0.1)
            // AND we are trying to move deeper (distProp < distCurr)
            // We block it. 
            // We use a small epsilon (0.001) to allow neutral movements but block penetration.
            if (distProp < 0.1 && distProp < distCurr - 0.001) {
                return true; // BLOCK: Moving deeper into wall
            }
        }
    }
    return false; // ALLOW
};

