// --- VECTOR MATH HELPERS ---
const sub = (a: Vector3, b: Vector3) => ({ x: a.x - b.x, y: a.y - b.y, z: a.z - b.z });
const add = (a: Vector3, b: Vector3) => ({ x: a.x + b.x, y: a.y + b.y, z: a.z + b.z });
const mul = (v: Vector3, s: number) => ({ x: v.x * s, y: v.y * s, z: v.z * s });

const rotateAroundAxis = (v: Vector3, axis: Vector3, angleDeg: number): Vector3 => {
  if (Math.abs(angleDeg) < 0.001) return v;
  const rad = (angleDeg * Math.PI) / 180;
  const cos = Math.cos(rad);
  const sin = Math.sin(rad);
  const k = normalize(axis);
  const kDotV = dotProduct(k, v);
  const kxV = crossProduct(k, v);
  const oneMinusCos = 1 - cos;

  return {
      x: v.x*cos + kxV.x*sin + k.x*kDotV*oneMinusCos,
      y: v.y*cos + kxV.y*sin + k.y*kDotV*oneMinusCos,
      z: v.z*cos + kxV.z*sin + k.z*kDotV*oneMinusCos
  };
};

const applyShortestArcRotation = (src: Vector3, dst: Vector3, toRotate: Vector3): Vector3 => {
  const s = normalize(src);
  const d = normalize(dst);
  const dot = dotProduct(s, d);
  if (dot > 0.9999) return toRotate;
  if (dot < -0.9999) {
      let axis = { x: 1, y: 0, z: 0 };
      if (Math.abs(s.x) > 0.9) axis = { x: 0, y: 1, z: 0 };
      const proj = dotProduct(axis, s);
      axis = { x: axis.x - s.x*proj, y: axis.y - s.y*proj, z: axis.z - s.z*proj };
      return rotateAroundAxis(toRotate, axis, 180);
  }
  const axis = crossProduct(s, d);
  const angleDeg = Math.acos(dot) * 180 / Math.PI;
  return rotateAroundAxis(toRotate, axis, angleDeg);
};

const getOppositeBone = (boneId: string): string | null => {
    if (boneId.startsWith('l')) return 'r' + boneId.slice(1);
    if (boneId.startsWith('r')) return 'l' + boneId.slice(1);
    return null;
};

// --- MATH HELPERS FOR IK ---
const createRootFrame = (dir: Vector3 = {x: 0, y: 1, z: 0}): Frame => {
    const u = normalize(dir);
    const neutralUp = { x: 0, y: 1, z: 0 };
    const neutralRight = { x: 1, y: 0, z: 0 };
    const neutralBack = { x: 0, y: 0, z: 1 };
    const right = applyShortestArcRotation(neutralUp, u, neutralRight);
    const back = applyShortestArcRotation(neutralUp, u, neutralBack);
    return { x: right, y: u, z: back };
};
const twistFrame = (frame: Frame, angleDeg: number): Frame => {
    if (!angleDeg || angleDeg === 0) return frame;
    return { x: rotateAroundAxis(frame.x, frame.y, angleDeg), y: frame.y, z: rotateAroundAxis(frame.z, frame.y, angleDeg) };
};
const localToWorld = (parentFrame: Frame, localVec: Vector3): Vector3 => {
    return {
        x: localVec.x * parentFrame.x.x + localVec.y * parentFrame.y.x + localVec.z * parentFrame.z.x,
        y: localVec.x * parentFrame.x.y + localVec.y * parentFrame.y.y + localVec.z * parentFrame.z.y,
        z: localVec.x * parentFrame.x.z + localVec.y * parentFrame.y.z + localVec.z * parentFrame.z.z
    };
};
const worldToLocal = (parentFrame: Frame, worldVec: Vector3): Vector3 => {
    return {
        x: dotProduct(worldVec, parentFrame.x),
        y: dotProduct(worldVec, parentFrame.y),
        z: dotProduct(worldVec, parentFrame.z)
    };
};
const transportFrame = (prevFrame: Frame, newDir: Vector3): Frame => {
    const u = normalize(newDir);
    const newRight = applyShortestArcRotation(prevFrame.y, u, prevFrame.x);
    const newBack = applyShortestArcRotation(prevFrame.y, u, prevFrame.z);
    return { x: newRight, y: u, z: newBack };
};

const solveTwoBoneIK = (
    root: Vector3, 
    target: Vector3, 
    l1: number, 
    l2: number, 
    pole: Vector3 
): { vec1: Vector3, vec2: Vector3 } | null => {
    const axis = normalize(sub(target, root));
    const dist = magnitude(sub(target, root));

    if (dist > l1 + l2 - 0.001) {
        // Unreachable: point at target
        return { vec1: axis, vec2: axis }; 
    }

    // Law of cosines to find angle at joint 1
    const cosAlpha = (l1*l1 + dist*dist - l2*l2) / (2 * l1 * dist);
    const alpha = Math.acos(Math.max(-1, Math.min(1, cosAlpha)));

    // Plane normal
    let normal = normalize(crossProduct(axis, pole));
    if (magnitude(normal) < 0.01) {
         // Pole is collinear with axis
         normal = normalize(crossProduct(axis, {x:0, y:1, z:0}));
    }

    // Rotate axis by alpha around normal to get bone1
    const vec1 = rotateAroundAxis(axis, normal, alpha * 180 / Math.PI);

    // Calculate Joint Position
    const jointPos = add(root, mul(vec1, l1));

    // Vec2 is direction from Joint to Target
    const vec2Global = normalize(sub(target, jointPos));

    return { vec1, vec2: vec2Global };
};

const BioModelPage: React.FC = () => {
  const [poseMode, setPoseMode] = useState<'start' | 'end'>('start');
  const [startPosture, setStartPosture] = useState<Posture>(DEFAULT_POSTURE);
  const [endPosture, setEndPosture] = useState<Posture>(DEFAULT_POSTURE);
  const [startTwists, setStartTwists] = useState<Record<string, number>>({});
  const [endTwists, setEndTwists] = useState<Record<string, number>>({});
  const [posture, setPosture] = useState<Posture>(DEFAULT_POSTURE);
  const [twists, setTwists] = useState<Record<string, number>>({});
  const [selectedBone, setSelectedBone] = useState<string | null>(null);
  const [targetPos, setTargetPos] = useState<Vector3 | null>(null);
  const [targetReferenceBone, setTargetReferenceBone] = useState<string | null>(null);

  const [symmetryMode, setSymmetryMode] = useState(false);
  const [bypassConstraints, setBypassConstraints] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [constraints, setConstraints] = useState<ConstraintConfig[]>([]);

  const [reactionForces, setReactionForces] = useState<VisualForce[]>([]);

  // Update posture based on pose mode change
  useEffect(() => {
    if (poseMode === 'start') {
      setPosture(startPosture);
      setTwists(startTwists);
    } else {
      setPosture(endPosture);
      setTwists(endTwists);
    }
  }, [poseMode]);

  // UI Helper States
  const isScapula = selectedBone ? selectedBone.includes('Clavicle') : false;
  const isHinge = selectedBone ? /Forearm|Tibia|Foot/.test(selectedBone) : false;

  const skeletalData = useMemo(() => {
    const locations: Record<string, Vector3> = {};
    const boneEndPoints: Record<string, Vector3> = {};
    const boneStartPoints: Record<string, Vector3> = {};
    const jointFrames: Record<string, Frame> = {};

    locations['Spine'] = { x: 0, y: CONFIG.TORSO_LEN/2, z: 0 };
    locations['pelvis'] = { x: 0, y: CONFIG.TORSO_LEN/2, z: 0 }; 
    const neckBase = { x: 0, y: -CONFIG.TORSO_LEN/2, z: 0 }; 
    locations['Neck'] = neckBase;

    boneStartPoints['spine'] = neckBase;
    boneEndPoints['spine'] = locations['Spine'];

    locations['lClavicle'] = neckBase;
    locations['rClavicle'] = neckBase;

    const lClavOffset = posture['lClavicle'] || { x: -25, y: 0, z: 0 };
    const rClavOffset = posture['rClavicle'] || { x: 25, y: 0, z: 0 };

    locations['lShoulder'] = { x: neckBase.x + lClavOffset.x, y: neckBase.y + lClavOffset.y, z: neckBase.z + lClavOffset.z };
    locations['rShoulder'] = { x: neckBase.x + rClavOffset.x, y: neckBase.y + rClavOffset.y, z: neckBase.z + rClavOffset.z };

    locations['lHip'] = { x: -CONFIG.HIP_WIDTH, y: CONFIG.TORSO_LEN/2, z: 0 };
    locations['rHip'] = { x: CONFIG.HIP_WIDTH, y: CONFIG.TORSO_LEN/2, z: 0 };

    const rootFrame = createRootFrame({x: 0, y: 1, z: 0});

    jointFrames['Spine'] = rootFrame;
    jointFrames['lClavicle'] = rootFrame;
    jointFrames['rClavicle'] = rootFrame;
    jointFrames['lShoulder'] = rootFrame;
    jointFrames['rShoulder'] = rootFrame;
    jointFrames['lHip'] = rootFrame;
    jointFrames['rHip'] = rootFrame;

    const calculateChain = (name: string, child: string, grandChild: string, start: Vector3, parentFrame: Frame, len1: number, len2: number, len3: number) => {
        const dir1Local = posture[name];
        const dir1World = localToWorld(parentFrame, dir1Local);
        const frame1Base = transportFrame(parentFrame, dir1World);
        const frame1Twisted = twistFrame(frame1Base, twists[name] || 0);
        const end1 = { x: start.x + frame1Twisted.y.x * len1, y: start.y + frame1Twisted.y.y * len1, z: start.z + frame1Twisted.y.z * len1 };
        boneStartPoints[name] = start;
        boneEndPoints[name] = end1;

        let end2 = end1;
        let frame2Twisted = frame1Twisted;
        if (child) {
            const dir2Local = posture[child];
            const dir2World = localToWorld(frame1Twisted, dir2Local); 
            const frame2Base = transportFrame(frame1Twisted, dir2World);
            frame2Twisted = twistFrame(frame2Base, twists[child] || 0);
            end2 = { x: end1.x + frame2Twisted.y.x * len2, y: end1.y + frame2Twisted.y.y * len2, z: end1.z + frame2Twisted.y.z * len2 };
            boneStartPoints[child] = end1;
            boneEndPoints[child] = end2;
        }
        if (grandChild) {
             const dir3Local = posture[grandChild] || {x:0, y:0, z:-1};
             const dir3World = localToWorld(frame2Twisted, dir3Local);
             const frame3Base = transportFrame(frame2Twisted, dir3World);
             const frame3Twisted = twistFrame(frame3Base, twists[grandChild] || 0);
             const end3 = { x: end2.x + frame3Twisted.y.x * len3, y: end2.y + frame3Twisted.y.y * len3, z: end2.z + frame3Twisted.y.z * len3 };
             boneStartPoints[grandChild] = end2;
             boneEndPoints[grandChild] = end3;
             return { end1, end2, end3, finalFrame: frame3Twisted, midFrame: frame2Twisted, frame1: frame1Twisted };
        }
        return { end1, end2, finalFrame: frame2Twisted, frame1: frame1Twisted };
    };

    const lLeg = calculateChain('lFemur', 'lTibia', 'lFoot', locations['lHip'], rootFrame, BONE_LENGTHS.lFemur, BONE_LENGTHS.lTibia, BONE_LENGTHS.lFoot);
    jointFrames['lKnee'] = lLeg.frame1; 
    jointFrames['lAnkle'] = lLeg.midFrame;

    const rLeg = calculateChain('rFemur', 'rTibia', 'rFoot', locations['rHip'], rootFrame, BONE_LENGTHS.rFemur, BONE_LENGTHS.rTibia, BONE_LENGTHS.rFoot);
    jointFrames['rKnee'] = rLeg.frame1;
    jointFrames['rAnkle'] = rLeg.midFrame;
    locations['rKnee'] = rLeg.end1;
    locations['rAnkle'] = rLeg.end2;

    const shoulderFrame = rootFrame; 
    const lArm = calculateChain('lHumerus', 'lForearm', '', locations['lShoulder'], shoulderFrame, BONE_LENGTHS.lHumerus, BONE_LENGTHS.lForearm, 0);
    locations['lElbow'] = lArm.end1;
    jointFrames['lElbow'] = lArm.frame1; 

    const rArm = calculateChain('rHumerus', 'rForearm', '', locations['rShoulder'], shoulderFrame, BONE_LENGTHS.rHumerus, BONE_LENGTHS.rForearm, 0);
    locations['rElbow'] = rArm.end1;
    jointFrames['rElbow'] = rArm.frame1;

    locations['lKnee'] = (boneEndPoints['lFemur']);
    locations['lAnkle'] = (boneEndPoints['lTibia']);

    return { locations, boneEndPoints, boneStartPoints, jointFrames };
  }, [posture, twists]);

  const updatePostureState = (updater: (prev: Posture) => Posture) => {
    if (poseMode === 'start') {
      setStartPosture(prev => {
        const next = updater(prev);
        setPosture(next); 
        return next;
      });
    } else {
      setEndPosture(prev => {
        const next = updater(prev);
        setPosture(next); 
        return next;
      });
    }
  };

  const applyConstraints = (boneId: string, proposedVec: Vector3): Vector3 => {
      if (bypassConstraints) return proposedVec;
      const constraint = constraints.find(c => c.boneId === boneId);
      if (!constraint) return proposedVec;
      if (constraint.type === 'vector' && constraint.restrictions.length > 0) {
          return posture[boneId]; 
      }
      return proposedVec;
  };

  const checkConstraintViolation = (boneId: string, proposedLocalVec: Vector3) => {
      if (bypassConstraints) return false;
      const constraint = constraints.find(c => c.boneId === boneId);
      if (!constraint || !skeletalData) return false;
      return false; 
  };

  const resolveKinematics = (boneId: string, proposedVector: Vector3, currentPosture: Posture): Posture | null => {
      return { ...currentPosture, [boneId]: proposedVector };
  };

  const handleScapulaChange = (axis: 'elevation' | 'protraction', val: number) => {
      if (!selectedBone) return;
      if (isPlaying) setIsPlaying(false);
      const current = posture[selectedBone];
      let newVec = { ...current };
      if (axis === 'elevation') newVec.y = -val;
      else if (axis === 'protraction') newVec.z = -val; 

      newVec = applyConstraints(selectedBone, newVec);

      const resolved = resolveKinematics(selectedBone, newVec, posture);
      if (!resolved) return; 

      updatePostureState(prev => {
          const next = { ...prev, ...resolved };
          if (symmetryMode) {
              const opp = getOppositeBone(selectedBone);
              if (opp) next[opp] = { x: -newVec.x, y: newVec.y, z: newVec.z };
          }
          return next;
      });
  };

  const handleHingeChange = (val: number) => {
      if (!selectedBone) return;
      if (isPlaying) setIsPlaying(false);
      let newVec = { x: 0, y: 0, z: 0 };
      const rad = (val * Math.PI) / 180;
      if (selectedBone.includes('Foot')) {
          newVec = { x: 0, y: -Math.sin(rad), z: -Math.cos(rad) };
      } else {
          const isKnee = selectedBone.includes('Tibia');
          const direction = isKnee ? 1 : -1; 
          newVec = { x: 0, y: Math.cos(rad), z: direction * Math.sin(rad) };
      }

      if (checkConstraintViolation(selectedBone, newVec)) return;

      const len = BONE_LENGTHS[selectedBone] || 100;
      setTargetPos({ x: newVec.x * len, y: newVec.y * len, z: newVec.z * len });
      updatePostureState(prev => {
          const next = { ...prev, [selectedBone]: newVec };
          if (symmetryMode) {
              const opp = getOppositeBone(selectedBone);
              if (opp) next[opp] = { ...newVec }; 
          }
          return next;
      });
  };

  const handlePointChange = (axis: keyof Vector3, newValue: number) => {
    if (!selectedBone || !targetPos) return;
    if (isPlaying) setIsPlaying(false);

    if (selectedBone.includes('Clavicle')) {
        const newVec = { ...posture[selectedBone], [axis]: newValue };
        const constrained = applyConstraints(selectedBone, newVec);
        setTargetPos(constrained);

        const resolved = resolveKinematics(selectedBone, constrained, posture);
        if (!resolved) return;

        updatePostureState(prev => {
            const next = { ...prev, ...resolved };
            if (symmetryMode) {
                const opp = getOppositeBone(selectedBone);
                if (opp) next[opp] = { x: -constrained.x, y: constrained.y, z: constrained.z };
            }
            return next;
        });
        return;
    }

    const internalVal = -newValue; 

    if (targetReferenceBone) {
        const newTarget = { ...targetPos, [axis]: internalVal };
        setTargetPos(newTarget); 
        const rootBone = targetReferenceBone;
        const childBone = selectedBone;
        const len1 = BONE_LENGTHS[rootBone];
        const len2 = BONE_LENGTHS[childBone];

        // Use current posture to determine pole vector roughly
        const currentPole = mul(posture[rootBone], len1); 
        if (magnitude(crossProduct(currentPole, newTarget)) < 0.1) {
             currentPole.z += 10; 
        }

        const solution = solveTwoBoneIK({x:0,y:0,z:0}, newTarget, len1, len2, currentPole);
        if (solution) {
            const newRootVec = solution.vec1;
            const rootFrame = createRootFrame({x:0, y:1, z:0});
            const transported = transportFrame(rootFrame, newRootVec);
            const newChildVecLocal = worldToLocal(transported, solution.vec2);

            updatePostureState(prev => {
                const next = { ...prev, [rootBone]: newRootVec, [childBone]: newChildVecLocal };
                if (symmetryMode) {
                    const oppRoot = getOppositeBone(rootBone);
                    const oppChild = getOppositeBone(childBone);
                    if (oppRoot) next[oppRoot] = { ...newRootVec, x: -newRootVec.x };
                    if (oppChild) next[oppChild] = { ...newChildVecLocal, x: -newChildVecLocal.x };
                }
                return next;
            });
        }
        return;
    }

    // Default: Single bone rotation or non-IK
    let newTarget = { ...targetPos, [axis]: internalVal };
    const constrainedTarget = applyConstraints(selectedBone, newTarget);
    setTargetPos(constrainedTarget);
    let direction = normalize(constrainedTarget);
    const bounds = BONE_CONSTRAINTS[selectedBone] || {};
    let constrained = { ...direction };
    if (bounds.x) constrained.x = Math.max(bounds.x[0], Math.min(bounds.x[1], constrained.x));
    if (bounds.y) constrained.y = Math.max(bounds.y[0], Math.min(bounds.y[1], constrained.y));
    if (bounds.z) constrained.z = Math.max(bounds.z[0], Math.min(bounds.z[1], constrained.z));
    const finalVector = normalize(constrained);

    const resolved = resolveKinematics(selectedBone, finalVector, posture);
    if (!resolved) return; 

    updatePostureState(prev => {
        const next = { ...prev, ...resolved };
        if (symmetryMode) {
            const opp = getOppositeBone(selectedBone);
            if (opp) next[opp] = { ...finalVector, x: -finalVector.x };
        }
        return next;
    });
  };

  const getHingeConfig = (bone: string) => {
      if (bone.includes('Forearm')) return { label: 'Elbow Flexion', min: 0, max: 140, default: 0 };
      if (bone.includes('Tibia')) return { label: 'Knee Flexion', min: 0, max: 140, default: 0 };
      if (bone.includes('Foot')) return { label: 'Ankle Dorsi/Plantar', min: -50, max: 50, default: 0 };
      return null;
  };

  const getCurrentHingeAngle = (bone: string) => {
      const vec = posture[bone] || { x: 0, y: 1, z: 0 };
      if (bone.includes('Foot')) {
          return Math.round(Math.asin(-vec.y) * 180 / Math.PI);
      }
      return Math.round(Math.acos(vec.y) * 180 / Math.PI);
  };

  const intentCoords = useMemo(() => {
    if (!targetPos) return { x: 0, y: 0, z: 0 };
    return { x: -Math.round(targetPos.x), y: -Math.round(targetPos.y), z: -Math.round(targetPos.z) };
  }, [targetPos]);

  return (
    <div className="flex flex-col h-screen bg-gray-50">
       <div className="flex-1 relative">
         <BioMan 
            posture={posture}
            twists={twists}
            selectedBone={selectedBone}
            onSelectBone={(b) => { setSelectedBone(b); setTargetPos(null); }}
            constraints={[]} 
            targetPos={targetPos}
            targetReferenceBone={targetReferenceBone}
         />

         <div className="absolute top-4 left-4 bg-white/90 backdrop-blur-sm p-4 rounded-2xl shadow-sm border border-gray-100">
           <div className="flex items-center gap-2 mb-4">
             <button 
                onClick={() => setPoseMode('start')}
                className={`px-3 py-1.5 rounded-lg text-xs font-bold uppercase tracking-wide ${poseMode === 'start' ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-500'}`}
             >
               Start
             </button>
             <button 
                onClick={() => setPoseMode('end')}
                className={`px-3 py-1.5 rounded-lg text-xs font-bold uppercase tracking-wide ${poseMode === 'end' ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-500'}`}
             >
               End
             </button>
           </div>

           {selectedBone ? (
             <div className="space-y-4">
               <h3 className="font-bold text-gray-900">{selectedBone}</h3>
               {isScapula ? (
                 <>
                   <div>
                     <label className="text-xs text-gray-500 block mb-1">Elevation</label>
                     <input type="range" min="-15" max="10" step="1" onChange={(e) => handleScapulaChange('elevation', parseInt(e.target.value))} className="w-full" />
                   </div>
                   <div>
                     <label className="text-xs text-gray-500 block mb-1">Protraction</label>
                     <input type="range" min="-15" max="10" step="1" onChange={(e) => handleScapulaChange('protraction', parseInt(e.target.value))} className="w-full" />
                   </div>
                 </>
               ) : isHinge ? (
                 <div>
                    <label className="text-xs text-gray-500 block mb-1">{getHingeConfig(selectedBone)?.label || 'Flexion'}</label>
                    <input 
                      type="range" 
                      min={getHingeConfig(selectedBone)?.min || 0} 
                      max={getHingeConfig(selectedBone)?.max || 140}
                      value={getCurrentHingeAngle(selectedBone)}
                      onChange={(e) => handleHingeChange(parseInt(e.target.value))} 
                      className="w-full" 
                    />
                 </div>
               ) : (
                 <div className="grid grid-cols-3 gap-2">
                   <div>
                     <label className="text-xs text-gray-500 block text-center">X</label>
                     <input type="number" value={intentCoords.x} onChange={(e) => handlePointChange('x', parseInt(e.target.value))} className="w-full p-1 text-center bg-gray-50 rounded" />
                   </div>
                   <div>
                     <label className="text-xs text-gray-500 block text-center">Y</label>
                     <input type="number" value={intentCoords.y} onChange={(e) => handlePointChange('y', parseInt(e.target.value))} className="w-full p-1 text-center bg-gray-50 rounded" />
                   </div>
                   <div>
                     <label className="text-xs text-gray-500 block text-center">Z</label>
                     <input type="number" value={intentCoords.z} onChange={(e) => handlePointChange('z', parseInt(e.target.value))} className="w-full p-1 text-center bg-gray-50 rounded" />
                   </div>
                 </div>
               )}
             </div>
           ) : (
             <p className="text-sm text-gray-400">Select a bone to edit</p>
           )}
         </div>
       </div>
    </div>
  );
};

export default BioModelPage;

// Helper to determine if a change makes the state *worse* (more violating)
// This prevents getting stuck if you start in an invalid state, but blocks moving further into violation
const checkPlanarViolation = (proposedPosture: Posture, proposedTwists: Record<string, number>, currentPosture: Posture, currentTwists: Record<string, number>): boolean => {
    const kProposed = calculateKinematics(proposedPosture, proposedTwists);
    const kCurrent = calculateKinematics(currentPosture, currentTwists);

    for (const [boneId, constraints] of Object.entries(hybridConstraints)) {
        const activeConstraints = (constraints as PlanarConstraint[]).filter(c => c.active);
        if (activeConstraints.length === 0) continue;

        const tipProp = kProposed.boneEndPoints[boneId];
        const tipCurr = kCurrent.boneEndPoints[boneId];
        if (!tipProp || !tipCurr) continue;

        for (const c of activeConstraints) {
            const N = normalize(c.normal);
            const vProp = sub(tipProp, c.center);
            const vCurr = sub(tipCurr, c.center);

            const distProp = dotProduct(vProp, N);
            const distCurr = dotProduct(vCurr, N);

            // Strict Check:
            // If we are "touching" or inside the wall (dist < 0.1)
            // AND we are trying to move deeper (distProp < distCurr)
            // We block it. 
            // We use a small epsilon (0.001) to allow neutral movements but block penetration.
            if (distProp < 0.1 && distProp < distCurr - 0.001) {
                return true; // BLOCK: Moving deeper into wall
            }
        }
    }
    return false; // ALLOW
};

const findSafeInteractionValue = (
    startVal: number,
    targetVal: number,
    checkFn: (val: number) => boolean
): number => {
    // 1. Optimistic check: If target is valid, return it immediately
    if (!checkFn(targetVal)) return targetVal;

    // 2. Binary search for the boundary between safe (startVal) and unsafe (targetVal)
    let low = startVal;
    let high = targetVal;
    let safe = startVal;

    // 10 iterations is plenty for UI slider precision
    for (let i = 0; i < 10; i++) {
        const mid = low + (high - low) / 2;
        if (checkFn(mid)) {
            // Mid is invalid (blocked), so the boundary is closer to start
            high = mid;
        } else {
            // Mid is valid, so update our "best known safe" and look further
            safe = mid;
            low = mid;
        }
    }
    return safe;
};

const validateConfiguration = (p: Posture, t: Record<string, number>): boolean => {
    return true;
};

const validatePosture = (p: Posture): boolean => {
    return validateConfiguration(p, twists);
};

const syncTwistsToPosture = (finalPosture: Posture, currentTwists: Record<string, number>): Record<string, number> => {
    return currentTwists;
};

const updatePostureState = (updater: (prev: Posture) => Posture) => {
  const updateFn = (setPostureFn: React.Dispatch<React.SetStateAction<Posture>>, setTwistFn: React.Dispatch<React.SetStateAction<Record<string, number>>>) => {
      setPostureFn(prev => {
          let next = updater(prev);
          next = solveConstraints(next, twists);
          if (!validatePosture(next)) return prev;
          setTwistFn(prevTwists => {
              const newTwists = syncTwistsToPosture(next, prevTwists);
              setTwists(newTwists);
              return newTwists;
          });
          setPosture(next); 
          return next;
      });
  };

  if (poseMode === 'start') {
      updateFn(setStartPosture, setStartTwists);
  } else {
      updateFn(setEndPosture, setEndTwists);
  }
};

const updateTwistState = (updater: (prev: Record<string, number>) => Record<string, number>) => {
    if (poseMode === 'start') { setStartTwists(updater); setTwists(updater); } 
    else { setEndTwists(updater); setTwists(updater); }
};

const skeletalData = useMemo(() => {
  return calculateKinematics(posture, twists);
}, [posture, twists]);

const applyConstraints = (boneId: string, proposedVec: Vector3): Vector3 => {
    // 1. Existing Vector Constraints
    let filtered = proposedVec;
    const constraint = constraints.find(c => c.boneId === boneId);
    if (constraint && constraint.type === 'vector' && constraint.restrictions.length > 0) {
         filtered = posture[boneId]; // Blocked
    }

    // 2. Hybrid Planar Constraints (Immediate interaction feedback)
    const planarConstraints = hybridConstraints[boneId] || [];
    const activePlanar = planarConstraints.filter(c => c.active);

    if (activePlanar.length === 0) return filtered;

    // Use current skeletal data for joint start position and frame
    const startPos = skeletalData.boneStartPoints[boneId];
    const parentFrame = skeletalData.jointFrames[boneId];
    const len = BONE_LENGTHS[boneId] || 0;

    if (!startPos || !parentFrame) return filtered;

    let currentLocal = filtered;

    // Run projection loop (simplified solver)
    for(let i=0; i<2; i++) {
        activePlanar.forEach(config => {
            const N = normalize(config.normal);
            const P_lock = config.center;
            const worldDir = localToWorld(parentFrame, currentLocal);
            const proposedTip = add(startPos, mul(worldDir, len));

            // Project logic copied from solveConstraints for consistency
            const vToStart = sub(startPos, P_lock);
            const distStart = dotProduct(vToStart, N);
            const circleCenter = sub(startPos, mul(N, distStart));
            const radSq = (len * len) - (distStart * distStart);

            let finalTip: Vector3;
            if (radSq < 0) {
                const dirToPlane = mul(N, -Math.sign(distStart));
                finalTip = add(startPos, mul(dirToPlane, len));
            } else {
                const radius = Math.sqrt(radSq);
                const vToProposed = sub(proposedTip, P_lock);
                const distProposed = dotProduct(vToProposed, N);
                const proposedOnPlane = sub(proposedTip, mul(N, distProposed));
                const vCenterToProposed = sub(proposedOnPlane, circleCenter);
                const mag = magnitude(vCenterToProposed);

                if (mag < 0.001) {
                    let arbitrary = crossProduct(N, {x:1, y:0, z:0});
                    if (magnitude(arbitrary) < 0.01) arbitrary = crossProduct(N, {x:0, y:1, z:0});
                    finalTip = add(circleCenter, mul(normalize(arbitrary), radius));
                } else {
                    finalTip = add(circleCenter, mul(vCenterToProposed, radius / mag));
                }
            }
            const finalWorldDir = normalize(sub(finalTip, startPos));
            currentLocal = worldToLocal(parentFrame, finalWorldDir);
        });
    }

    return currentLocal;
};

const handleScapulaChange = (axis: 'elevation' | 'protraction', val: number) => {
    if (!selectedBone) return;
    if (isPlaying) setIsPlaying(false);

    const current = posture[selectedBone];
    let newVec = { ...current };
    if (axis === 'elevation') newVec.y = -val;
    else if (axis === 'protraction') newVec.z = -val; 

    // Look-ahead check
    const proposedPosture = { ...posture, [selectedBone]: newVec };
    if (checkPlanarViolation(proposedPosture, twists, posture, twists)) {
        return; // Strictly block input
    }

    newVec = applyConstraints(selectedBone, newVec);

    const parentFrame = skeletalData.jointFrames[selectedBone];
    const proposedWorld = localToWorld(parentFrame, newVec);
    const finalLocal = worldToLocal(parentFrame, proposedWorld);

    updatePostureState(prev => {
        const next = { ...prev, [selectedBone]: finalLocal };
        if (symmetryMode) {
            const opp = getOppositeBone(selectedBone);
            if (opp) next[opp] = { x: -finalLocal.x, y: finalLocal.y, z: finalLocal.z };
        }
        return next;
    });
};

const handleHingeChange = (val: number) => {
    if (!selectedBone) return;
    if (isPlaying) setIsPlaying(false);

    const currentAngle = getCurrentHingeAngle(selectedBone);

    const safeAngle = findSafeInteractionValue(currentAngle, val, (testAngle) => {
        let testVec = { x: 0, y: 0, z: 0 };
        const rad = (testAngle * Math.PI) / 180;
        if (selectedBone.includes('Foot')) {
            testVec = { x: 0, y: Math.sin(rad), z: -Math.cos(rad) };
        } else {
            const direction = 1; 
            testVec = { x: 0, y: Math.cos(rad), z: direction * Math.sin(rad) };
        }
        const proposedPosture = { ...posture, [selectedBone]: testVec };
        return checkPlanarViolation(proposedPosture, twists, posture, twists);
    });

    let newVec = { x: 0, y: 0, z: 0 };
    const rad = (safeAngle * Math.PI) / 180;
    if (selectedBone.includes('Foot')) {
        newVec = { x: 0, y: Math.sin(rad), z: -Math.cos(rad) };
    } else {
        const direction = 1; 
        newVec = { x: 0, y: Math.cos(rad), z: direction * Math.sin(rad) };
    }

    const constrainedVec = applyConstraints(selectedBone, newVec);

    updatePostureState(prev => {
        const next = { ...prev, [selectedBone]: constrainedVec };
        if (symmetryMode) {
            const opp = getOppositeBone(selectedBone);
            if (opp) next[opp] = { ...constrainedVec }; 
        }
        return next;
    });
};

const addHybridConstraint = (boneId: string) => {
    const tip = skeletalData.boneEndPoints[boneId] || {x:0, y:0, z:0};
    const newConstraint: PlanarConstraint = {
        id: Date.now().toString(),
        active: true,
        normal: { x: 0, y: 0, z: 1 },
        center: tip
    };
    setHybridConstraints(prev => ({
        ...prev,
        [boneId]: [...(prev[boneId] || []), newConstraint]
    }));
};

const updatePlanarConstraint = (boneId: string, constraintId: string, updates: Partial<PlanarConstraint>) => {
    setHybridConstraints(prev => ({
        ...prev,
        [boneId]: (prev[boneId] || []).map(c => c.id === constraintId ? { ...c, ...updates } : c)
    }));
};

const removePlanarConstraint = (boneId: string, constraintId: string) => {
    setHybridConstraints(prev => ({
        ...prev,
        [boneId]: (prev[boneId] || []).filter(c => c.id !== constraintId)
    }));
};

const lockedPlanes = useMemo<VisualPlane[]>(() => {
  const planes: VisualPlane[] = [];
  const entries = Object.entries(hybridConstraints);
  for (const [boneId, constraintList] of entries) {
      if (!Array.isArray(constraintList)) continue;
      constraintList.forEach((config, idx) => {
          if (config.active) {
              planes.push({
                  id: `plane-${config.id}`,
                  center: config.center,
                  normal: normalize(config.normal),
                  size: 200,
                  color: idx % 2 === 0 ? '#8b5cf6' : '#ec4899'
              });
          }
      });
  }
  return planes;
}, [hybridConstraints]);

const handlePointChange = (axis: keyof Vector3, newValue: number) => {
  if (!selectedBone || !targetPos) return;
  if (isPlaying) setIsPlaying(false);

  if (selectedBone.includes('Clavicle')) {
      const proposedPos = { ...posture[selectedBone], [axis]: newValue };
      const constrainedPos = applyConstraints(selectedBone, proposedPos);
      setTargetPos(constrainedPos);
      updatePostureState(prev => {
          const next = { ...prev, [selectedBone]: constrainedPos };
          if (symmetryMode) {
              const opp = getOppositeBone(selectedBone);
              if (opp) next[opp] = { x: -constrainedPos.x, y: constrainedPos.y, z: constrainedPos.z };
          }
          return next;
      });
      return;
  }

  const internalVal = -newValue;
  const newTarget = { ...targetPos, [axis]: internalVal };
  setTargetPos(newTarget);

  if (targetReferenceBone) {
      const rootBone = targetReferenceBone;
      const childBone = selectedBone; 

      const isRootConstrained = constraints.some(c => c.boneId === rootBone);
      const isChildConstrained = constraints.some(c => c.boneId === childBone); 
      let middleBone = '';
      if (rootBone.includes('Femur')) middleBone = rootBone.replace('Femur', 'Tibia');
      else if (rootBone.includes('Humerus')) middleBone = rootBone.replace('Humerus', 'Forearm');
      const isMiddleConstrained = constraints.some(c => c.boneId === middleBone);

      if (isRootConstrained || isMiddleConstrained) return; 

      const len1 = BONE_LENGTHS[rootBone];
      const len2 = BONE_LENGTHS[middleBone];

      let newRootVec = posture[rootBone];
      let newMidVecLocal = posture[middleBone];

      const isRight = rootBone.startsWith('r');
      const targetDirWorld = normalize(newTarget);

      // Use uniform Neutral Frame generation for both limbs to maintain consistent rotation signs
      let baseFrame: Frame;
      if (rootBone.includes('Humerus') || rootBone.includes('Femur')) {
           baseFrame = createRootFrame(targetDirWorld);
      } else {
           const rootFrame = createRootFrame({x:0, y:1, z:0});
           baseFrame = transportFrame(rootFrame, targetDirWorld);
      }

      // Use Clamped Twist for IK Calculation to ensure kinematic consistency
      let currentTwist = twists[rootBone] || 0;
      if (ROTATION_LIMITS[rootBone]) {
          currentTwist = clamp(currentTwist, ROTATION_LIMITS[rootBone].min, ROTATION_LIMITS[rootBone].max);
      }

      // Invert twist for left side before calculation
      let calcTwist = currentTwist;
      if (rootBone.startsWith('l')) calcTwist = -calcTwist;

      const twistedFrame = twistFrame(baseFrame, calcTwist);

      let biasScale = 1;
      if (rootBone.includes('Femur')) {
          biasScale = -1;
      } else {
          biasScale = 1;
      }

      const dynamicBias = mul(twistedFrame.z, biasScale); 

      const forwardSolution = solveTwoBoneIK({x:0,y:0,z:0}, newTarget, len1, len2, dynamicBias);

      if (forwardSolution) {
          const rootFrame = createRootFrame({x:0, y:1, z:0});
          newRootVec = worldToLocal(rootFrame, forwardSolution.vec1);

          let frame1: Frame;
          if (rootBone.includes('Humerus') || rootBone.includes('Femur')) {
              frame1 = createRootFrame(forwardSolution.vec1);
          } else {
              frame1 = transportFrame(rootFrame, forwardSolution.vec1);
          }

          // The child's local vector must be relative to the TWISTED parent frame
          const frame1Twisted = twistFrame(frame1, calcTwist);
          newMidVecLocal = worldToLocal(frame1Twisted, forwardSolution.vec2);
      }

      updatePostureState(prev => {
          const next = { ...prev, [rootBone]: newRootVec, [middleBone]: newMidVecLocal };
          if (symmetryMode) {
              const oppRoot = getOppositeBone(rootBone);
              const oppMid = getOppositeBone(middleBone);
              if (oppRoot) next[oppRoot] = { ...newRootVec, x: -newRootVec.x };
              if (oppMid) next[oppMid] = { ...newMidVecLocal, x: -newMidVecLocal.x };
          }
          return next;
      });
      return;
  }

  const newDirLocal = normalize(newTarget);
  const constrainedLocal = applyConstraints(selectedBone, newDirLocal);

  updatePostureState(prev => {
      const next = { ...prev, [selectedBone]: constrainedLocal };
      if (symmetryMode) {
          const opp = getOppositeBone(selectedBone);
          if (opp) next[opp] = { ...constrainedLocal, x: -constrainedLocal.x };
      }
      return next;
  });
};

const handleRotationChange = (val: number) => {
  if (!selectedBone) return;
  if (isPlaying) setIsPlaying(false);

  const currentP = poseMode === 'start' ? startPosture : endPosture;
  const currentT = poseMode === 'start' ? startTwists : endTwists;

  let allowedVal = val;
  if (ROTATION_LIMITS[selectedBone]) {
      allowedVal = clamp(val, ROTATION_LIMITS[selectedBone].min, ROTATION_LIMITS[selectedBone].max);
  }

  const startVal = currentT[selectedBone] !== undefined ? currentT[selectedBone] : 0;

  const safeTwist = findSafeInteractionValue(startVal, allowedVal, (testTwist) => {
      const nextTwists = { ...currentT, [selectedBone]: testTwist };
      if (symmetryMode) {
          const opp = getOppositeBone(selectedBone);
          if (opp) nextTwists[opp] = testTwist;
      }
      return checkPlanarViolation(currentP, nextTwists, currentP, currentT);
  });

  const newTwist = safeTwist;
  const nextTwists = { ...currentT, [selectedBone]: newTwist };
  if (symmetryMode) {
      const opp = getOppositeBone(selectedBone);
      if (opp) nextTwists[opp] = newTwist;
  }

  const resolvedPosture = solveConstraints(currentP, nextTwists);

  if (!validateConfiguration(resolvedPosture, nextTwists)) return;

  if (poseMode === 'start') {
      setStartPosture(resolvedPosture);
      setStartTwists(nextTwists);
  } else {
      setEndPosture(resolvedPosture);
      setEndTwists(nextTwists);
  }
  setPosture(resolvedPosture);
  setTwists(nextTwists);
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import BioMan, { Posture, Vector3, VisualForce, VisualConstraint, VisualPlane } from '../components/BioMan';
// icons
import { Play, Pause, RefreshCw, ChevronDown, ChevronUp } from 'lucide-react';

// --- MATH HELPERS ---
const normalize = (v: Vector3): Vector3 => {
  const len = Math.sqrt(v.x * v.x + v.y * v.y + v.z * v.z);
  if (len === 0) return { x: 0, y: 1, z: 0 };
  return { x: v.x / len, y: v.y / len, z: v.z / len };
};
const sub = (a: Vector3, b: Vector3) => ({ x: a.x - b.x, y: a.y - b.y, z: a.z - b.z });
const add = (a: Vector3, b: Vector3) => ({ x: a.x + b.x, y: a.y + b.y, z: a.z + b.z });
const mul = (v: Vector3, s: number) => ({ x: v.x * s, y: v.y * s, z: v.z * s });
const dotProduct = (a: Vector3, b: Vector3): number => a.x * b.x + a.y * b.y + a.z * b.z;
const crossProduct = (a: Vector3, b: Vector3): Vector3 => ({
  x: a.y * b.z - a.z * b.y,
  y: a.z * b.x - a.x * b.z,
  z: a.x * b.y - a.y * b.x
});
const magnitude = (v: Vector3): number => Math.sqrt(v.x * v.x + v.y * v.y + v.z * v.z);
const clamp = (val: number, min: number, max: number) => Math.min(Math.max(val, min), max);

// --- TYPES & CONSTANTS ---
interface PlanarConstraint {
  id: string;
  active: boolean;
  normal: Vector3;
  center: Vector3;
}

interface Frame {
    x: Vector3;
    y: Vector3;
    z: Vector3;
}

const DEFAULT_POSTURE: Posture = {
  lClavicle: { x: -25, y: 0, z: 0 },
  rClavicle: { x: 25, y: 0, z: 0 },
  lHumerus: { x: 0, y: 1, z: 0 },
  lForearm: { x: 0, y: 1, z: 0 },
  rHumerus: { x: 0, y: 1, z: 0 },
  rForearm: { x: 0, y: 1, z: 0 },
  lFemur: { x: 0, y: 1, z: 0 },
  lTibia: { x: 0, y: 1, z: 0 },
  lFoot: { x: 0, y: 0, z: -1 },
  rFemur: { x: 0, y: 1, z: 0 },
  rTibia: { x: 0, y: 1, z: 0 },
  rFoot: { x: 0, y: 0, z: -1 },
};

const BONE_LENGTHS: Record<string, number> = {
  lClavicle: 25, rClavicle: 25,
  lHumerus: 44, lForearm: 39,
  rHumerus: 44, rForearm: 39,
  lFemur: 54, lTibia: 49, lFoot: 20,
  rFemur: 54, rTibia: 49, rFoot: 20
};

const CONFIG = {
  TORSO_LEN: 60,
  HIP_WIDTH: 20
};

const ROTATION_LIMITS: Record<string, { min: number; max: number }> = {
  lForearm: { min: 0, max: 140 },
  rForearm: { min: 0, max: 140 },
  lTibia: { min: 0, max: 140 },
  rTibia: { min: 0, max: 140 },
  lFoot: { min: -50, max: 50 },
  rFoot: { min: -50, max: 50 }
};

// --- ROTATION HELPERS ---
const rotateAroundAxis = (v: Vector3, axis: Vector3, angleDeg: number): Vector3 => {
  if (Math.abs(angleDeg) < 0.001) return v;
  const rad = (angleDeg * Math.PI) / 180;
  const cos = Math.cos(rad);
  const sin = Math.sin(rad);
  const k = normalize(axis);
  const kDotV = dotProduct(k, v);
  const kxV = crossProduct(k, v);
  const oneMinusCos = 1 - cos;
  return {
      x: v.x*cos + kxV.x*sin + k.x*kDotV*oneMinusCos,
      y: v.y*cos + kxV.y*sin + k.y*kDotV*oneMinusCos,
      z: v.z*cos + kxV.z*sin + k.z*kDotV*oneMinusCos
  };
};

const applyShortestArcRotation = (src: Vector3, dst: Vector3, toRotate: Vector3): Vector3 => {
  const s = normalize(src);
  const d = normalize(dst);
  const dot = dotProduct(s, d);
  if (dot > 0.9999) return toRotate;
  if (dot < -0.9999) {
      let axis = { x: 1, y: 0, z: 0 };
      if (Math.abs(s.x) > 0.9) axis = { x: 0, y: 1, z: 0 };
      const proj = dotProduct(axis, s);
      axis = { x: axis.x - s.x*proj, y: axis.y - s.y*proj, z: axis.z - s.z*proj };
      return rotateAroundAxis(toRotate, axis, 180);
  }
  const axis = crossProduct(s, d);
  const angleDeg = Math.acos(dot) * 180 / Math.PI;
  return rotateAroundAxis(toRotate, axis, angleDeg);
};

// --- FRAME HELPERS ---
const createRootFrame = (dir: Vector3 = {x: 0, y: 1, z: 0}): Frame => {
    const u = normalize(dir);
    const neutralUp = { x: 0, y: 1, z: 0 };
    const neutralRight = { x: 1, y: 0, z: 0 };
    const neutralBack = { x: 0, y: 0, z: 1 };
    const right = applyShortestArcRotation(neutralUp, u, neutralRight);
    const back = applyShortestArcRotation(neutralUp, u, neutralBack);
    return { x: right, y: u, z: back };
};
const twistFrame = (frame: Frame, angleDeg: number): Frame => {
    if (!angleDeg || angleDeg === 0) return frame;
    return { x: rotateAroundAxis(frame.x, frame.y, angleDeg), y: frame.y, z: rotateAroundAxis(frame.z, frame.y, angleDeg) };
};
const localToWorld = (parentFrame: Frame, localVec: Vector3): Vector3 => {
    return {
        x: localVec.x * parentFrame.x.x + localVec.y * parentFrame.y.x + localVec.z * parentFrame.z.x,
        y: localVec.x * parentFrame.x.y + localVec.y * parentFrame.y.y + localVec.z * parentFrame.z.y,
        z: localVec.x * parentFrame.x.z + localVec.y * parentFrame.y.z + localVec.z * parentFrame.z.z
    };
};
const worldToLocal = (parentFrame: Frame, worldVec: Vector3): Vector3 => {
    return {
        x: dotProduct(worldVec, parentFrame.x),
        y: dotProduct(worldVec, parentFrame.y),
        z: dotProduct(worldVec, parentFrame.z)
    };
};
const transportFrame = (prevFrame: Frame, newDir: Vector3): Frame => {
    const u = normalize(newDir);
    const newRight = applyShortestArcRotation(prevFrame.y, u, prevFrame.x);
    const newBack = applyShortestArcRotation(prevFrame.y, u, prevFrame.z);
    return { x: newRight, y: u, z: newBack };
};

const getOppositeBone = (boneId: string): string | null => {
    if (boneId.startsWith('l')) return 'r' + boneId.slice(1);
    if (boneId.startsWith('r')) return 'l' + boneId.slice(1);
    return null;
};

// --- KINEMATICS CALCULATOR ---
const calculateKinematics = (posture: Posture, twists: Record<string, number>) => {
    const locations: Record<string, Vector3> = {};
    const boneEndPoints: Record<string, Vector3> = {};
    const boneStartPoints: Record<string, Vector3> = {};
    const jointFrames: Record<string, Frame> = {};

    locations['Spine'] = { x: 0, y: CONFIG.TORSO_LEN/2, z: 0 };
    const neckBase = { x: 0, y: -CONFIG.TORSO_LEN/2, z: 0 }; 
    locations['Neck'] = neckBase;

    boneStartPoints['spine'] = neckBase;
    boneEndPoints['spine'] = locations['Spine'];

    const rootFrame = createRootFrame({x: 0, y: 1, z: 0});

    jointFrames['Spine'] = rootFrame;
    jointFrames['lClavicle'] = rootFrame;
    jointFrames['rClavicle'] = rootFrame;
    jointFrames['lShoulder'] = rootFrame;
    jointFrames['rShoulder'] = rootFrame;
    jointFrames['lHip'] = rootFrame;
    jointFrames['rHip'] = rootFrame;

    const lClavOffset = posture['lClavicle'] || { x: -25, y: 0, z: 0 };
    const rClavOffset = posture['rClavicle'] || { x: 25, y: 0, z: 0 };

    locations['lShoulder'] = { x: neckBase.x + lClavOffset.x, y: neckBase.y + lClavOffset.y, z: neckBase.z + lClavOffset.z };
    locations['rShoulder'] = { x: neckBase.x + rClavOffset.x, y: neckBase.y + rClavOffset.y, z: neckBase.z + rClavOffset.z };
    locations['lHip'] = { x: -CONFIG.HIP_WIDTH, y: CONFIG.TORSO_LEN/2, z: 0 };
    locations['rHip'] = { x: CONFIG.HIP_WIDTH, y: CONFIG.TORSO_LEN/2, z: 0 };

    const calculateChain = (name: string, child: string, grandChild: string, start: Vector3, parentFrame: Frame, len1: number, len2: number, len3: number) => {
        const dir1Local = posture[name];
        const dir1World = localToWorld(parentFrame, dir1Local);
        const frame1Base = transportFrame(parentFrame, dir1World);
        const frame1Twisted = twistFrame(frame1Base, twists[name] || 0);
        const end1 = { x: start.x + frame1Twisted.y.x * len1, y: start.y + frame1Twisted.y.y * len1, z: start.z + frame1Twisted.y.z * len1 };
        boneStartPoints[name] = start;
        boneEndPoints[name] = end1;

        let end2 = end1;
        let frame2Twisted = frame1Twisted;
        if (child) {
            const dir2Local = posture[child];
            const dir2World = localToWorld(frame1Twisted, dir2Local); 
            const frame2Base = transportFrame(frame1Twisted, dir2World);
            frame2Twisted = twistFrame(frame2Base, twists[child] || 0);
            end2 = { x: end1.x + frame2Twisted.y.x * len2, y: end1.y + frame2Twisted.y.y * len2, z: end1.z + frame2Twisted.y.z * len2 };
            boneStartPoints[child] = end1;
            boneEndPoints[child] = end2;
        }
        if (grandChild) {
             const dir3Local = posture[grandChild] || {x:0, y:0, z:-1};
             const dir3World = localToWorld(frame2Twisted, dir3Local);
             const frame3Base = transportFrame(frame2Twisted, dir3World);
             const frame3Twisted = twistFrame(frame3Base, twists[grandChild] || 0);
             const end3 = { x: end2.x + frame3Twisted.y.x * len3, y: end2.y + frame3Twisted.y.y * len3, z: end2.z + frame3Twisted.y.z * len3 };
             boneStartPoints[grandChild] = end2;
             boneEndPoints[grandChild] = end3;
             return { end1, end2, end3, finalFrame: frame3Twisted, midFrame: frame2Twisted, frame1: frame1Twisted };
        }
        return { end1, end2, finalFrame: frame2Twisted, frame1: frame1Twisted };
    };

    const lLeg = calculateChain('lFemur', 'lTibia', 'lFoot', locations['lHip'], rootFrame, BONE_LENGTHS.lFemur, BONE_LENGTHS.lTibia, BONE_LENGTHS.lFoot);
    jointFrames['lKnee'] = lLeg.frame1; 
    jointFrames['lAnkle'] = lLeg.midFrame;

    const rLeg = calculateChain('rFemur', 'rTibia', 'rFoot', locations['rHip'], rootFrame, BONE_LENGTHS.rFemur, BONE_LENGTHS.rTibia, BONE_LENGTHS.rFoot);
    jointFrames['rKnee'] = rLeg.frame1;
    jointFrames['rAnkle'] = rLeg.midFrame;

    const shoulderFrame = rootFrame; 
    const lArm = calculateChain('lHumerus', 'lForearm', '', locations['lShoulder'], shoulderFrame, BONE_LENGTHS.lHumerus, BONE_LENGTHS.lForearm, 0);
    jointFrames['lElbow'] = lArm.frame1; 

    const rArm = calculateChain('rHumerus', 'rForearm', '', locations['rShoulder'], shoulderFrame, BONE_LENGTHS.rHumerus, BONE_LENGTHS.rForearm, 0);
    jointFrames['rElbow'] = rArm.frame1;

    return { locations, boneEndPoints, boneStartPoints, jointFrames };
};

const BioModelPage: React.FC = () => {
  // State
  const [poseMode, setPoseMode] = useState<'start' | 'end'>('start');
  const [startPosture, setStartPosture] = useState<Posture>(DEFAULT_POSTURE);
  const [endPosture, setEndPosture] = useState<Posture>(DEFAULT_POSTURE);
  const [startTwists, setStartTwists] = useState<Record<string, number>>({});
  const [endTwists, setEndTwists] = useState<Record<string, number>>({});

  const [posture, setPosture] = useState<Posture>(DEFAULT_POSTURE);
  const [twists, setTwists] = useState<Record<string, number>>({});

  const [selectedBone, setSelectedBone] = useState<string | null>(null);
  const [targetPos, setTargetPos] = useState<Vector3 | null>(null);
  const [targetReferenceBone, setTargetReferenceBone] = useState<string | null>(null);
  const [symmetryMode, setSymmetryMode] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);

  const [hybridConstraints, setHybridConstraints] = useState<Record<string, PlanarConstraint[]>>({});

  useEffect(() => {
    if (poseMode === 'start') {
      setPosture(startPosture);
      setTwists(startTwists);
    } else {
      setPosture(endPosture);
      setTwists(endTwists);
    }
  }, [poseMode, startPosture, endPosture, startTwists, endTwists]);

  // Derived
  const skeletalData = useMemo(() => calculateKinematics(posture, twists), [posture, twists]);

  // Logic
  const checkPlanarViolation = (proposedPosture: Posture, proposedTwists: Record<string, number>, currentPosture: Posture, currentTwists: Record<string, number>): boolean => {
      const kProposed = calculateKinematics(proposedPosture, proposedTwists);
      const kCurrent = calculateKinematics(currentPosture, currentTwists);

      for (const [boneId, constraints] of Object.entries(hybridConstraints)) {
          const activeConstraints = constraints.filter(c => c.active);
          if (activeConstraints.length === 0) continue;

          const tipProp = kProposed.boneEndPoints[boneId];
          const tipCurr = kCurrent.boneEndPoints[boneId];
          if (!tipProp || !tipCurr) continue;

          for (const c of activeConstraints) {
              const N = normalize(c.normal);
              const vProp = sub(tipProp, c.center);
              const vCurr = sub(tipCurr, c.center);
              const distProp = dotProduct(vProp, N);
              const distCurr = dotProduct(vCurr, N);

              if (distProp < 0.1 && distProp < distCurr - 0.001) {
                  return true; 
              }
          }
      }
      return false;
  };

  const findSafeInteractionValue = (
      startVal: number,
      targetVal: number,
      checkFn: (val: number) => boolean
  ): number => {
      if (!checkFn(targetVal)) return targetVal;
      let low = startVal;
      let high = targetVal;
      let safe = startVal;
      for (let i = 0; i < 10; i++) {
          const mid = low + (high - low) / 2;
          if (checkFn(mid)) {
              high = mid;
          } else {
              safe = mid;
              low = mid;
          }
      }
      return safe;
  };

  const applyConstraints = (boneId: string, proposedVec: Vector3): Vector3 => {
      // 1. Existing Vector Constraints
      // (Placeholder for now as constraints prop is empty)

      // 2. Hybrid Planar Constraints
      const planarConstraints = hybridConstraints[boneId] || [];
      const activePlanar = planarConstraints.filter(c => c.active);

      if (activePlanar.length === 0) return proposedVec;

      const startPos = skeletalData.boneStartPoints[boneId];
      const parentFrame = skeletalData.jointFrames[boneId];
      const len = BONE_LENGTHS[boneId] || 0;

      if (!startPos || !parentFrame) return proposedVec;

      let currentLocal = proposedVec;

      for(let i=0; i<2; i++) {
          activePlanar.forEach(config => {
              const N = normalize(config.normal);
              const P_lock = config.center;
              const worldDir = localToWorld(parentFrame, currentLocal);
              const proposedTip = add(startPos, mul(worldDir, len));

              const vToStart = sub(startPos, P_lock);
              const distStart = dotProduct(vToStart, N);
              const circleCenter = sub(startPos, mul(N, distStart));
              const radSq = (len * len) - (distStart * distStart);

              let finalTip: Vector3;
              if (radSq < 0) {
                  const dirToPlane = mul(N, -Math.sign(distStart));
                  finalTip = add(startPos, mul(dirToPlane, len));
              } else {
                  const radius = Math.sqrt(radSq);
                  const vToProposed = sub(proposedTip, P_lock);
                  const distProposed = dotProduct(vToProposed, N);
                  const proposedOnPlane = sub(proposedTip, mul(N, distProposed));
                  const vCenterToProposed = sub(proposedOnPlane, circleCenter);
                  const mag = magnitude(vCenterToProposed);

                  if (mag < 0.001) {
                      let arbitrary = crossProduct(N, {x:1, y:0, z:0});
                      if (magnitude(arbitrary) < 0.01) arbitrary = crossProduct(N, {x:0, y:1, z:0});
                      finalTip = add(circleCenter, mul(normalize(arbitrary), radius));
                  } else {
                      finalTip = add(circleCenter, mul(vCenterToProposed, radius / mag));
                  }
              }
              const finalWorldDir = normalize(sub(finalTip, startPos));
              currentLocal = worldToLocal(parentFrame, finalWorldDir);
          });
      }
      return currentLocal;
  };

  const solveConstraints = (p: Posture, t: Record<string, number>): Posture => {
      // Basic solver iteration
      let solved = { ...p };
      // Iterate through bones to apply constraints
      // Simplified: Just apply local constraints to current posture
      Object.keys(hybridConstraints).forEach(boneId => {
          if (solved[boneId]) {
             solved[boneId] = applyConstraints(boneId, solved[boneId]);
          }
      });
      return solved;
  };

  const validateConfiguration = (p: Posture, t: Record<string, number>): boolean => {
      // Reuse checkPlanarViolation for now, assuming current valid state is passed or we ignore history
      // Ideally we check against static collision geometry
      return !checkPlanarViolation(p, t, p, t);
  };

  const validatePosture = (p: Posture): boolean => {
      return validateConfiguration(p, twists);
  };

  const syncTwistsToPosture = (finalPosture: Posture, currentTwists: Record<string, number>): Record<string, number> => {
      return currentTwists;
  };

  const updatePostureState = (updater: (prev: Posture) => Posture) => {
    const updateFn = (setPostureFn: React.Dispatch<React.SetStateAction<Posture>>, setTwistFn: React.Dispatch<React.SetStateAction<Record<string, number>>>) => {
        setPostureFn(prev => {
            let next = updater(prev);
            next = solveConstraints(next, twists);
            // if (!validatePosture(next)) return prev; // validation might be too strict without context

            setTwistFn(prevTwists => {
                const newTwists = syncTwistsToPosture(next, prevTwists);
                setTwists(newTwists);
                return newTwists;
            });
            setPosture(next); 
            return next;
        });
    };

    if (poseMode === 'start') {
        updateFn(setStartPosture, setStartTwists);
    } else {
        updateFn(setEndPosture, setEndTwists);
    }
  };

  // Handlers
  const handleScapulaChange = (axis: 'elevation' | 'protraction', val: number) => {
      if (!selectedBone) return;
      if (isPlaying) setIsPlaying(false);

      const current = posture[selectedBone];
      let newVec = { ...current };
      if (axis === 'elevation') newVec.y = -val;
      else if (axis === 'protraction') newVec.z = -val; 

      const proposedPosture = { ...posture, [selectedBone]: newVec };
      if (checkPlanarViolation(proposedPosture, twists, posture, twists)) {
          return; 
      }

      newVec = applyConstraints(selectedBone, newVec);

      updatePostureState(prev => {
          const next = { ...prev, [selectedBone]: newVec };
          if (symmetryMode) {
              const opp = getOppositeBone(selectedBone);
              if (opp) next[opp] = { x: -newVec.x, y: newVec.y, z: newVec.z };
          }
          return next;
      });
  };

  const handleHingeChange = (val: number) => {
      if (!selectedBone) return;
      if (isPlaying) setIsPlaying(false);

      const getCurrentAngle = () => {
        const vec = posture[selectedBone] || {x:0,y:1,z:0};
        if (selectedBone.includes('Foot')) return Math.round(Math.asin(-vec.y) * 180 / Math.PI);
        return Math.round(Math.acos(vec.y) * 180 / Math.PI);
      };
      const currentAngle = getCurrentAngle();

      const safeAngle = findSafeInteractionValue(currentAngle, val, (testAngle) => {
          let testVec = { x: 0, y: 0, z: 0 };
          const rad = (testAngle * Math.PI) / 180;
          if (selectedBone.includes('Foot')) {
              testVec = { x: 0, y: -Math.sin(rad), z: -Math.cos(rad) };
          } else {
              const isKnee = selectedBone.includes('Tibia');
              const direction = isKnee ? 1 : -1; 
              testVec = { x: 0, y: Math.cos(rad), z: direction * Math.sin(rad) };
          }
          const proposedPosture = { ...posture, [selectedBone]: testVec };
          return checkPlanarViolation(proposedPosture, twists, posture, twists);
      });

      let newVec = { x: 0, y: 0, z: 0 };
      const rad = (safeAngle * Math.PI) / 180;
      if (selectedBone.includes('Foot')) {
          newVec = { x: 0, y: -Math.sin(rad), z: -Math.cos(rad) };
      } else {
          const isKnee = selectedBone.includes('Tibia');
          const direction = isKnee ? 1 : -1; 
          newVec = { x: 0, y: Math.cos(rad), z: direction * Math.sin(rad) };
      }

      const constrainedVec = applyConstraints(selectedBone, newVec);

      updatePostureState(prev => {
          const next = { ...prev, [selectedBone]: constrainedVec };
          if (symmetryMode) {
              const opp = getOppositeBone(selectedBone);
              if (opp) next[opp] = { ...constrainedVec }; 
          }
          return next;
      });
  };

  const handlePointChange = (axis: keyof Vector3, newValue: number) => {
    if (!selectedBone || !targetPos) return;
    if (isPlaying) setIsPlaying(false);

    if (selectedBone.includes('Clavicle')) {
        const proposedPos = { ...posture[selectedBone], [axis]: newValue };
        const constrainedPos = applyConstraints(selectedBone, proposedPos);
        setTargetPos(constrainedPos);
        updatePostureState(prev => {
            const next = { ...prev, [selectedBone]: constrainedPos };
            if (symmetryMode) {
                const opp = getOppositeBone(selectedBone);
                if (opp) next[opp] = { x: -constrainedPos.x, y: constrainedPos.y, z: constrainedPos.z };
            }
            return next;
        });
        return;
    }

    // Simplified logic for point change
    const internalVal = -newValue;
    const newTarget = { ...targetPos, [axis]: internalVal };
    setTargetPos(newTarget);

    const newDirLocal = normalize(newTarget);
    const constrainedLocal = applyConstraints(selectedBone, newDirLocal);

    updatePostureState(prev => {
        const next = { ...prev, [selectedBone]: constrainedLocal };
        if (symmetryMode) {
            const opp = getOppositeBone(selectedBone);
            if (opp) next[opp] = { ...constrainedLocal, x: -constrainedLocal.x };
        }
        return next;
    });
  };

  const getHingeConfig = (bone: string) => {
      if (bone.includes('Forearm')) return { label: 'Elbow Flexion', min: 0, max: 140, default: 0 };
      if (bone.includes('Tibia')) return { label: 'Knee Flexion', min: 0, max: 140, default: 0 };
      if (bone.includes('Foot')) return { label: 'Ankle Dorsi/Plantar', min: -50, max: 50, default: 0 };
      return null;
  };

  const getCurrentHingeAngle = (bone: string) => {
      const vec = posture[bone] || { x: 0, y: 1, z: 0 };
      if (bone.includes('Foot')) {
          return Math.round(Math.asin(-vec.y) * 180 / Math.PI);
      }
      return Math.round(Math.acos(vec.y) * 180 / Math.PI);
  };

  const intentCoords = useMemo(() => {
    if (!targetPos) return { x: 0, y: 0, z: 0 };
    return { x: -Math.round(targetPos.x), y: -Math.round(targetPos.y), z: -Math.round(targetPos.z) };
  }, [targetPos]);

  // Derived visuals
  const planes = useMemo<VisualPlane[]>(() => {
    const p: VisualPlane[] = [];
    Object.entries(hybridConstraints).forEach(([boneId, list]) => {
        list.forEach((c, idx) => {
            if (c.active) {
                p.push({
                    id: `plane-${c.id}`,
                    center: c.center,
                    normal: normalize(c.normal),
                    size: 200,
                    color: idx % 2 === 0 ? '#8b5cf6' : '#ec4899'
                });
            }
        });
    });
    return p;
  }, [hybridConstraints]);

  return (
    <div className="flex flex-col h-screen bg-gray-50">
       <div className="flex-1 relative">
         <BioMan 
            posture={posture}
            twists={twists}
            selectedBone={selectedBone}
            onSelectBone={(b) => { setSelectedBone(b); setTargetPos(null); }}
            constraints={[]} 
            planes={planes}
            targetPos={targetPos}
            targetReferenceBone={targetReferenceBone}
         />

         {/* UI Controls Overlay */}
         <div className="absolute top-4 left-4 bg-white/90 backdrop-blur-sm p-4 rounded-2xl shadow-sm border border-gray-100 w-64">
           <div className="flex items-center gap-2 mb-4">
             <button 
                onClick={() => setPoseMode('start')}
                className={`flex-1 px-3 py-1.5 rounded-lg text-xs font-bold uppercase tracking-wide transition-colors ${poseMode === 'start' ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-500 hover:bg-gray-200'}`}
             >
               Start
             </button>
             <button 
                onClick={() => setPoseMode('end')}
                className={`flex-1 px-3 py-1.5 rounded-lg text-xs font-bold uppercase tracking-wide transition-colors ${poseMode === 'end' ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-500 hover:bg-gray-200'}`}
             >
               End
             </button>
           </div>

           {selectedBone ? (
             <div className="space-y-4">
               <div className="flex justify-between items-center">
                 <h3 className="font-bold text-gray-900">{selectedBone}</h3>
                 <button onClick={() => setSelectedBone(null)} className="text-gray-400 hover:text-gray-600 text-xs">Clear</button>
               </div>

               {(selectedBone.includes('Clavicle')) ? (
                 <>
                   <div>
                     <label className="text-xs text-gray-500 block mb-1">Elevation</label>
                     <input type="range" min="-15" max="10" step="1" onChange={(e) => handleScapulaChange('elevation', parseInt(e.target.value))} className="w-full accent-indigo-600" />
                   </div>
                   <div>
                     <label className="text-xs text-gray-500 block mb-1">Protraction</label>
                     <input type="range" min="-15" max="10" step="1" onChange={(e) => handleScapulaChange('protraction', parseInt(e.target.value))} className="w-full accent-indigo-600" />
                   </div>
                 </>
               ) : (getHingeConfig(selectedBone)) ? (
                 <div>
                    <label className="text-xs text-gray-500 block mb-1">{getHingeConfig(selectedBone)?.label}</label>
                    <input 
                      type="range" 
                      min={getHingeConfig(selectedBone)?.min} 
                      max={getHingeConfig(selectedBone)?.max}
                      value={getCurrentHingeAngle(selectedBone)}
                      onChange={(e) => handleHingeChange(parseInt(e.target.value))} 
                      className="w-full accent-indigo-600" 
                    />
                 </div>
               ) : (
                 <div className="grid grid-cols-3 gap-2">
                   <div>
                     <label className="text-xs text-gray-500 block text-center mb-1">X</label>
                     <input type="number" value={intentCoords.x} onChange={(e) => handlePointChange('x', parseInt(e.target.value))} className="w-full p-1 text-center bg-gray-50 rounded border border-gray-200 text-sm" />
                   </div>
                   <div>
                     <label className="text-xs text-gray-500 block text-center mb-1">Y</label>
                     <input type="number" value={intentCoords.y} onChange={(e) => handlePointChange('y', parseInt(e.target.value))} className="w-full p-1 text-center bg-gray-50 rounded border border-gray-200 text-sm" />
                   </div>
                   <div>
                     <label className="text-xs text-gray-500 block text-center mb-1">Z</label>
                     <input type="number" value={intentCoords.z} onChange={(e) => handlePointChange('z', parseInt(e.target.value))} className="w-full p-1 text-center bg-gray-50 rounded border border-gray-200 text-sm" />
                   </div>
                 </div>
               )}

               <div className="flex items-center gap-2 mt-4 pt-4 border-t border-gray-100">
                  <input type="checkbox" checked={symmetryMode} onChange={(e) => setSymmetryMode(e.target.checked)} className="rounded text-indigo-600 focus:ring-indigo-500" />
                  <span className="text-xs text-gray-600">Symmetry Mode</span>
               </div>
             </div>
           ) : (
             <p className="text-sm text-gray-400 italic">Select a bone to edit controls.</p>
           )}
         </div>
       </div>
    </div>
  );
};

